#295, 305-306, 337-346, 348-359</li><li><a href="/bob-rozakis/4040-46810/" data-ref-id="4040-46810">Bob Rozakis</a> #305-306, 334, 336</li><li><a href="/steve-englehart/4040-42211/" data-ref-id="4040-42211">Steve Englehart</a> #311</li><li><a href="/roger-mckenzie/4040-44822/" data-ref-id="4040-44822">Roger McKenzie</a> #325</li><li><a href="/mike-w-barr/4040-41455/" data-ref-id="4040-41455">Mike W. Barr</a> #327, 329, 331, 334, 353</li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478">Marv Wolfman</a> #328-335</li><li><a href="/roy-thomas/4040-42067/" data-ref-id="4040-42067">Roy Thomas</a> #336-338, 340</li><li><a href="/robin-snyder/4040-68071/" data-ref-id="4040-68071">Robin Snyder</a> #341, 347</li><li><a href="/bruce-jones/4040-30846/" data-ref-id="4040-30846">Bruce Jones</a> #345-346, 348-351</li><li><a href="/roger-slifer/4040-43760/" data-ref-id="4040-43760">Roger Slifer</a> #347</li><li><a href="/paul-levitz/4040-41154/" data-ref-id="4040-41154">Paul Levitz</a> #350-351</li><li><a href="/paul-kupperberg/4040-44124/" data-ref-id="4040-44124">Paul Kupperberg</a> #352-353</li><li><a href="/doug-moench/4040-42016/" data-ref-id="4040-42016">Doug Moench</a> #360-400</li></ul><p><b>Post Crisis</b></p><ul><li><a href="/barbara-randall-kesel/4040-42187/" data-ref-id="4040-42187">Barbara Randall Kesel</a> #401</li><li><a href="https://comicvine.gamespot.com/frank-miller/4040-7082/" data-ref-id="4040-7082">Frank Miller</a> #404-407 (4)</li><li><a href="https://comicvine.gamespot.com/max-allan-collins/4040-56814/" data-ref-id="4040-56814">Max Allen Collins</a> #402-403, 408-412 (7)</li><li><a href="https://comicvine.gamespot.com/mary-jo-duffy/4040-51725/" data-ref-id="4040-51725">Mary Jo Duffy</a> #413</li><li><a href="https://comicvine.gamespot.com/jim-starlin/4040-7922/" data-ref-id="4040-7922">Jim Starlin</a> #414-430 <strong>(17)</strong></li><li><a href="https://comicvine.gamespot.com/christopher-priest/4040-41500/" data-ref-id="4040-41500">Christo