INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2045', 'Fantastic Four', 'The Fantastic Four!', '31', '<p>The Fantastic Four were created in response to <a href="/dc-comics/4010-10/" data-ref-id="4010-10">DC''s</a> <a href="/justice-league-of-america/4060-31815/" data-ref-id="4060-31815">Justice League</a> and soon became the <a href="/silver-age-of-comics/4015-55821/" data-ref-id="4015-55821">Silver Age''s</a> premier superhero team. <a href="/stan-lee/4040-40467/" data-ref-id="4040-40467">Stan Lee</a> and <a href="/jack-kirby/4040-5614/" data-ref-id="4040-5614">Jack Kirby</a> collaborated on the opening 102 issues of the magazine, and told the adventures of Mr. Fantastic, the Thing, Invisible Woman and the Human Torch. This first volume ran through issue <a href="/fantastic-four-416-onslaught-phase-2-unfinished-bu/4000-77596/" data-ref-id="4000-77596">#416</a>, before it was rebooted as <a href="/fantastic-four-vol-2/4050-9462/" data-ref-id="4050-9462">Fantastic Four (vol. 2)</a> (13 issues) as part of the short lived <a href="/heroes-reborn/4045-55955/" data-ref-id="4045-55955">Heroes Reborn</a> arc. The series was restarted again with issue 1 in <a href="/fantastic-four/4050-6211/" data-ref-id="4050-6211">Fantastic Four (vol. 3)</a> before it reverted back to the original numbering with issue <a href="/fantastic-four-500-unthinkable-part-4/4000-139097/" data-ref-id="4000-139097">#500</a>.</p><p>Writers</p><ul><li>Stan Lee #1-115, 120-125, 154, 180, 189, 296</li><li>Archie Goodwin #115-118, 182</li><li>Roy Thomas #119, 126-133, 136, 137, 157-171, 173-179, 181, 303</li><li>Gerry Conway #133-152, 179</li><li>Tony Isabellla #153</li><li>Len Wein #154-157, 182-188, 191-194</li><li>Bill Mantlo #172, 182-183, 193, 194, 216-218</li><li>Mike Friedrich #177</li><li>James Shooter #182, 183, 296</li><li>Roger Stern #183, 294, 295, 297-302</li><li>Ralph Macchio #183 w// Roger Silfer</li><li>Marv Wolfman #190, 195-217</li><li>Keith Pollard #193, 194</li><li>Doug Moench #219, 222-231</li><li>John Byrne #220, 221, 232-294</li><li>Steve Englehart #304-333</li><li>Walt Simonson #334-341, 343-350, 352-354</li><li>Tom Defalco #301, 302, 356-393, 395-416</li><li>Danny Fingeroth #342, 355</li><li>Len Kaminski #351</li><li>Mike Lackey #388, 390, 394</li></ul><h4>Collected Editions</h4><p><strong><a href="/marvel-masterworks-the-fantastic-four/4050-35197/" data-ref-id="4050-35197">Marvel Masterworks: The Fantastic Four</a></strong></p><ul><li>Vol. 1 (#1-10)</li><li>Vol. 2 (#11-20)</li><li>Vol. 3 (#21-30)</li><li>Vol. 4 (#31-40)</li><li>Vol. 5 (#41-50)</li><li>Vol. 6 (#51-60)</li><li>Vol. 7 (#61-71)</li><li>Vol. 8 (#72-81)</li><li>Vol. 9 (#82-93)</li><li>Vol. 10 (#94-104)</li><li>Vol. 11 (#105-116)</li><li>Vol. 12 (#117-128)</li><li>Vol. 13 (#129-141)</li><li>Vol. 14 (#142-150)</li><li>Vol. 15 (#151-163)</li><li>Vol. 16 (#164-175)</li><li>Vol. 17 (#176-191)</li><li>Vol. 18 (#192-203)</li><li>Vol. 19 (#204-218)</li><li>Vol. 20 (#219-231)</li><li>Vol. 21 (#232-240)</li><li>Vol. 22 (#241-250)</li><li>Vol. 23 (#251-257)</li></ul><p><strong>Epic Collection:</strong></p><ul><li>Vol. 1: <a href="/fantastic-four-epic-collection-the-worlds-greatest/4050-76910/" data-ref-id="4050-76910">The World''s Greatest Comic Mag</a><a href="/fantastic-four-epic-collection-the-worlds-greatest/4050-76910/" data-ref-id="4050-76910">azine</a> (#1-18)</li><li>Vol. 2: <a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-master-plan-of-/4050-102458/" data-ref-id="4050-102458">The Master Plan of Doctor Doom</a>(#19-32)</li><li>Vol. 3: <a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-coming-of-galac/4050-112582/">The Coming of Galactus</a> (#33-51)</li><li>Vol. 4: <a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-mystery-of-the-/4050-120815/">The Mystery of the Black Panther</a> (#52-67)</li><li>Vol. 5: <a href="https://comicvine.gamespot.com/f