INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2128', 'The Avengers', 'The Coming of the Avengers', '31', '<p>The first Avengers ongoing series, the one that started the Earth''s Mightiest Heroes'' campaign for justice and freedom. They will save the world, and if they can''t, they will avenge it. And there came a day, a day unlike any other when Earth''s mightiest heroes joined forces to face the threats no single superhero could withstand! The Avengers were born!</p><p>The first volume of the Avengers lasted from 1963 until 1996 and ran for 402 issues. This ended during the <a href="/onslaught/4045-43814/" data-ref-id="4045-43814">Onslaught</a> storyline and was continued in <a href="/avengers/4050-6742/" data-ref-id="4050-6742">Avengers Volume 2</a>.</p><h4>Collected Editions</h4><p><a href="/marvel-masterworks-avengers/4050-23401/" data-ref-id="4050-23401">Marvel Masterworks: Avengers</a></p><ul><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-1-volume-one/4000-140582/" data-ref-id="4000-140582">Vol. 1</a> (#1-10)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-2-volume-two/4000-140583/" data-ref-id="4000-140583">Vol. 2</a> (#11-20)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-3-volume-three/4000-140584/" data-ref-id="4000-140584">Vol. 3</a> (#21-30)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-4-volume-four/4000-140387/" data-ref-id="4000-140387">Vol. 4</a> (#31-40)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-5-volume-five/4000-140388/" data-ref-id="4000-140388">Vol. 5</a> (#41-50, King-Size Special #1)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-6-volume-six/4000-140389/" data-ref-id="4000-140389">Vol. 6</a> (#51-58, King-Size Special #2)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-7-volume-seven/4000-140390/" data-ref-id="4000-140390">Vol. 7</a> (#59-68)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-8-volume-eight/4000-232258/" data-ref-id="4000-232258">Vol. 8</a> (#69-79)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-9-volume-nine/4000-232259/" data-ref-id="4000-232259">Vol. 9</a> (#80-88)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-10-volume-ten/4000-232260/" data-ref-id="4000-232260">Vol. 10</a> (#89-100)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-11-volume-eleven/4000-342274/" data-ref-id="4000-342274">Vol. 11</a> (#101-111)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-12-volume-twelve/4000-342277/" data-ref-id="4000-342277">Vol. 12</a> (#112-119)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-13-volume-13/4000-412226/" data-ref-id="4000-412226">Vol. 13</a> (#120-128, Giant-Size #1)</li><li><a href="https://www.comicvine.com/marvel-masterworks-avengers-14-volume-14/4000-460712/" data-ref-id="4000-460712">Vol. 14</a> (#129-135, Giant-Size #2-4)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-15-volume-15/4000-486335/" data-ref-id="4000-486335">Vol. 15</a> (#136-149)</li><li><a href="/marvel-masterworks-avengers-16-volume-16/4000-535357/" data-ref-id="4000-535357">Vol. 16</a> (#150-163)</li><li><a href="/marvel-masterworks-avengers-17-volume-17/4000-613795/" data-ref-id="4000-613795">Vol. 17</a> (#164-177)</li><li><a href="/marvel-masterworks-avengers-18-volume-18/4000-665917/" data-ref-id="4000-665917">Vol. 18</a> (#178-188)</li></ul><ul><li><a href="/avengers-the-vibranium-collection/4050-81281/" data-ref-id="4050-81281">Avengers: The Vibranium Collection</a> (#1, 4, 16, 57-58, 164-166, 273-277)</li><li><a href="https://www.comicvine.com/avengers-earths-mightiest-heroes/4050-78105/" data-ref-id="4050-78105">Avengers: Earth''s Mightiest Heroes</a> (#1-20)</li><li><a href="https://comicvine.gamespot.com/in