INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2129', 'Fantastic Four Annual', 'Sub-Mariner Versus the Human Race!; The Fabulous Fantastic Four Meet Spider-Man!; The Fantastic Four', '31', '<p>Annual for <a href="https://comicvine.gamespot.com/fantastic-four/4050-2045/" data-ref-id="4050-2045">Fantastic Four</a>.</p><p>The series ran from 1963-1994 for twenty-seven issues. From 1995 til 1997 there was no annual for this series. From 1998 til 2001 the FF annual''s had unique indicia titles;</p><ul><li><a href="//www.comicvine.com/fantastic-four-fantastic-4-98/4050-60493/" data-ref-id="4050-60493">Fantastic Four / Fantastic 4 ''98</a></li><li><a href="//www.comicvine.com/fantastic-four-1999/4050-60494/" data-ref-id="4050-60494">Fantastic Four 1999</a></li><li><a href="//www.comicvine.com/fantastic-four-2000/4050-60495/" data-ref-id="4050-60495">Fantastic Four 2000</a></li><li><a href="//www.comicvine.com/fantastic-four-2001/4050-60496/" data-ref-id="4050-60496">Fantastic Four 2001</a></li></ul><p>The series resumed in 2010 with issue #32. A new <a href="https://www.comicvine.com/fantastic-four-annual/4050-77247/">Fantastic Four Annual </a>series started in 2014 with a new number 1.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-the-fantastic-four-2-volume-two/4000-232241/" data-ref-id="4000-232241">Marvel Masterworks: Fantastic Four Vol. 2</a> (#1)</li><li><a href="https://comicvine.gamespot.com/namor-the-sub-mariner-epic-collection-enter-the-su/4050-135436/">Namor, The Sub-Mariner Epic Collection: Enter The Sub-Mariner</a> (#1)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-master-plan-of-/4050-102458/" data-ref-id="4050-102458">Fantastic Four Epic Collection: The Master Plan of Doctor Doom</a> (#1-2)</li><li><a href="/marvel-masterworks-the-fantastic-four-4-volume-fou/4000-232243/" data-ref-id="4000-232243">Marvel Masterworks: Fantastic Four, Vol. 4</a> (#2)</li><li><a href="/marvel-masterworks-the-fantastic-four-5-volume-fiv/4000-232244/" data-ref-id="4000-232244">Marvel Masterworks: Fantastic Four, Vol. 5</a> (#3)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-coming-of-galac/4050-112582/">Fantastic Four Epic Collection: The Coming of Galactus</a> (#3)</li><li><a href="https://comicvine.gamespot.com/marvel-weddings/4050-137619/">Marvel Weddings</a> (#3)</li><li><a href="/marvel-masterworks-the-fantastic-four-6-volume-six/4000-232080/" data-ref-id="4000-232080">Marvel Masterworks: Fantastic Four, Vol. 6</a> (#4)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-mystery-of-the-/4050-120815/">Fantastic Four Epic Collection: The Mystery of the Black Panther</a> (#4-5)</li><li><a href="/marvel-masterworks-the-fantastic-four-7-volume-sev/4000-232245/" data-ref-id="4000-232245">Marvel Masterworks: Fantastic Four, Vol. 7</a> (#5)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby </a>(#5)</li><li><a href="https://www.comicvine.com/fantastic-four-omnibus-3-volume-three/4000-487393/" data-ref-id="4000-487393">Fantastic Four Omnibus Vol. 3</a> (#5-7)</li><li><a href="https://comicvine.gamespot.com/kirby-is-fantastic/4050-119384/">Kirby Is... Fantastic!</a> (#6)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-name-is-doom/4050-126609/">Fantastic Four Epic Collection: The Name Is Doom</a> (#6)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-at-war-with-atlanti/4050-131537/">Fantastic Four Epic Collection: At War With Atlantis</a> (#7)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#11)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-fantastic-four-18-volume-18/4000-549517/" data-ref-id="4000-549517">Marvel Masterworks: Fantastic Four, Vol. 18</a> (#12-13)</li><li><a href="/avengers-the-legacy-of-thanos/4050-74816/" data-ref-id="4050-74816">Avengers: The Legacy of Thanos</a> (#19)</li><li><a href="https://comicvine.gamespot.com/secret-invasion-rise-of-the-skrulls/4050-112466/">Secret Invasion: Rise of the Skrulls</a> (#19)</li><li><a href="https://comicvine.gamespot.com/avengers-vs-fantastic-four/4050-123278/">Avengers vs. Fantastic Four</a> (#19)</li><li><a href="//www.comicvine.com/fantastic-four-epic-collection-all-in-the-family/4050-70951/" data-ref-id="4050-70951">Fantastic Four Epic Collection: All In the Family</a> (#20)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-more-things-cha/4050-119753/">Fantastic Four Epic Collection: The More Things Change...</a> (#21)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-into-the-time-strea/4050-76010/" data-ref-id="4050-76010">Fantastic Four Epic Collection: Into the Time Stream</a> (#23)</li><li><a href="//www.comicvine.com/guardians-of-the-galaxy-by-jim-valentino-1-volume-/4000-441868/" data-ref-id="4000-441868">Guardians of the Galaxy By Jim Valentino vol. 1</a> (#24)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-the-new-fantastic-f/4050-111826/">Fantastic Four Epic Collection: The New Fantastic Four</a> (#24)</li><li><a href="https://comicvine.gamespot.com/fantastic-four-epic-collection-this-flame-this-fur/4050-139958/">Fantastic Four Epic Collection: This Flame, This Fury</a> (#25-26)</li><li><a href="https://comicvine.gamespot.com/marvel-tales-by-alan-davis/4050-106204/" data-ref-id="4050-106204">Marvel Tales by Alan Davis</a> (#33)</li><li><a href="https://comicvine.gamespot.com/clandestine-family-ties/4050-113696/">ClanDestine: Family Ties</a> (#33)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/80-jahre-marvel-3-die-1960er-aufbruch-in-eine-neue/4000-713394/">80 Jahre Marvel - Die 1960er: Aufbruch in eine neue Zeit </a>(#1) (German)</li><li><a href="https://comicvine.gamespot.com/kingsize-kirby/4050-104017/" data-ref-id="4050-104017">King-Size Kirby</a> (#5) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-60-los-4-fantasticos-d/4000-612268/">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 2</a> (#17) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-61-los-4-fantasticos-d/4000-612269/">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 3</a> (#18-19) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-79-guardianes-de-la-ga/4000-612317/">Coleccionable Marvel Héroes - Guardianes de la Galaxia 1: La búsqueda del escudo</a> (#24) (Spanish)</li><li><a href="https://comicvine.gamespot.com/marvel-deluxe-los-4-fantasticos-el-maestro-de-muer/4050-104691/">Marvel Deluxe. Los 4 Fantásticos: El maestro de Muerte</a> (#32) (Spanish)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa-3/4000-285470/" data-ref-id="4000-285470">#11</a> &amp; <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa-13/4000-285480/" data-ref-id="4000-285480">#16</a> have been translated into Spanish.</p>', '1963', '29', 'https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/4106202-untitled.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2133', 'The X-Men', 'X-Men', '31', '<p>The comic that started it all for the X-Men. For the first 66 issues, the series starred the team of Cyclops, Marvel Girl, Angel, Beast, Iceman and Professor Xavier, with Havok and Polaris joining near the end of the run.</p><p>Unfortunately, due to falling sales and lack of interest for the comic, the series started publishing reprints from earlier adventures with issue #67. This kept on up to issue #93. With X-Men issue #94, the New X-Men team was brought into the comic after they had starred in their first adventure in <a href="//www.comicvine.com/giant-size-x-men-1-deadly-genesis/4000-14890/" data-ref-id="4000-14890"> Giant-Size X-Men</a> issue #1. Beginning with issue #114 the descriptive "Uncanny" was added to the cover treatment but it wasn''t until issue #142 that the volume''s official name was permanently changed, via the indicia, to Uncanny X-Men. The series continues in <a href="/uncanny-x-men/4050-3092/" data-ref-id="4050-3092"><strong><em>The Uncanny X-Men</em></strong></a> with issue #142.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/x-men-omnibus-1-volume-one/4000-167612/" data-ref-id="4000-167612">X-Men Omnibus Volume 1</a>#1-31</li><li><a href="/marvel-masterworks-the-x-men/4050-35213/" data-ref-id="4050-35213">Marvel Masterworks: X-Men</a> Vol. 1 (#1-10)</li><li><a href="/xmen-epic-collection-children-of-the-atom/4050-79108/" data-ref-id="4050-79108">X-Men Epic Collection: Children of the Atom</a> (#1-23)</li><li><a href="https://comicvine.gamespot.com/x-men-adventures/4050-112834/">X-Men Adventures</a> (#1 &amp; 19)</li><li><a href="https://comicvine.gamespot.com/x-men-we-are-the-x-men/4050-35334/">X-Men: We Are the X-Men</a> (#1 &amp; 129)</li><li><a href="/mighty-marvel-masterworks-the-x-men-1-the-stranges/4000-881496/" data-ref-id="4000-881496">Mighty Marvel Masterworks: The X-Men: The Strangest Super-Heroes of All</a> (#1-10)</li><li><a href="https://comicvine.gamespot.com/namor-the-sub-mariner-epic-collection-enter-the-su/4050-135436/">Namor, The Sub-Mariner Epic Collection: Enter The Sub-Mariner</a> (#6)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#9)</li><li>Marvel Masterworks: X-Men, Vol. 2 (#11-21)</li><li>Marvel Masterworks: X-Men, Vol. 3 (#22-31)</li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-lonely-are-the-hunted/4050-96317/" data-ref-id="4050-96317">X-Men Epic Collection: Lonely Are The Hunted</a> (#24-45)</li><li><a href="https://comicvine.gamespot.com/x-men-omnibus-2-volume-two/4000-273105/" data-ref-id="4000-273105">X-Men Omnibus Volume 2</a> #32-66</li><li>Marvel Masterworks: X-Men, Vol. 4 (#32-42)</li><li><a href="https://comicvine.gamespot.com/decades-marvel-in-the-60s-spider-man-meets-the-mar/4050-117580/">Decades: Marvel In the ''60s: Spider-Man Meets the Marvel Universe</a> (#35)</li><li>Marvel Masterworks: X-Men, Vol. 5 (#43-53)</li><li><a href="/avengers-omnibus-2-volume-two/4000-482859/" data-ref-id="4000-482859">Avengers Omnibus Volume 2</a> (#45)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-masters-of-evil/4050-100962/" data-ref-id="4050-100962">Avengers Epic Collection: The Masters of Evil</a> (#45)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-the-sentinels-live/4050-115289/">X-Men Epic Collection: The Sentinels Live</a> (#46-66)</li><li>Marvel Masterworks: X-Men, Vol. 6 (#54-66)</li><li><a href="https://comicvine.gamespot.com/x-men-by-roy-thomas-and-neal-adams-gallery-edition/4050-121265/">X-Men by Roy Thomas &amp; Neal Adams Gallery Edition</a> (#56-57 (A Stories), 58-63 &amp; 65)</li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-1-volume-1/4000-167686/" data-ref-id="4000-167686">The Uncanny X-Men Volume 1</a> #94-131</li><li><a href="/marvel-masterworks-the-uncanny-x-men/4050-30807/" data-ref-id="4050-30807">Marvel Masterworks: Uncanny X-Men</a>, Vol. 1 (#94-100)</li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#94-110)</li><li><a href="https://comicvine.gamespot.com/x-men-the-dark-phoenix-saga-omnibus/4050-112607/">X-Men: The Dark Phoenix Saga Omnibus</a> (#97-105, 107-108 &amp; 125-138)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 2 (#101-110)</li><li><a href="https://comicvine.gamespot.com/x-men-starjammers-by-dave-cockrum/4050-122501/">X-Men: Starjammers by Dave Cockrum</a> (#107-108)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#109, 120-121 &amp; 139-140)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 3 (#111-121)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-proteus/4050-129905/">X-Men Epic Collection: Proteus</a> (#111-128)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 4 (#122-131)</li><li><a href="/marvel-masterworks-dazzler-1-volume-1/4000-742426/" data-ref-id="4000-742426">Marvel Masterworks: Dazzler Volume 1</a> (#130-131)</li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-2-volume-2/4000-450781/" data-ref-id="4000-450781">The Uncanny X-Men Volume 2</a> #132-141</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 5 (#132-140)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-lives-again-omnibus/4050-131205/">Marvel Horror Lives Again! Omnibus</a> (#13-140)</li><li>Marvel Masterworks: Uncanny X-Men, Vol. 6 (#141-150)</li><li><a href="/x-men-proteus/4050-28480/" data-ref-id="4050-28480">X:Men: Proteus</a> (#125-128)</li><li><a href="/x-men-the-dark-phoenix-saga/4050-30096/" data-ref-id="4050-30096">X-Men: The Dark Phoenix Saga</a> (#129-137)</li><li><a href="https://comicvine.gamespot.com/x-men-milestones-dark-phoenix-saga/4050-119891/">X-Men Milestones: Dark Phoenix Saga</a> (#129-137)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-the-fate-of-the-phoenix/4050-134230/">X-Men Epic Collection: The Fate of the Phoenix</a> (#129-143)</li><li><a href="/x-men-days-of-future-past/4050-34959/" data-ref-id="4050-34959">X-Men: Days of Future Past</a> (#138-141)</li><li><a href="https://comicvine.gamespot.com/wolverine-first-class-to-russia-with-love/4050-36517/">Wolverine: First Class: To Russia, With Love</a> (#139-140)</li></ul><h4>Omnibus</h4><ul><li><a href="https://comicvine.gamespot.com/x-men-omnibus-1-volume-one/4000-167612/" data-ref-id="4000-167612">X-Men Omnibus Volume 1</a>#1-31</li><li><a href="https://comicvine.gamespot.com/x-men-omnibus-2-volume-two/4000-273105/" data-ref-id="4000-273105">X-Men Omnibus Volume 2</a> #32-66</li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-1-volume-1/4000-167686/" data-ref-id="4000-167686">The Uncanny X-Men Volume 1</a> #94-131</li><li><a href="https://comicvine.gamespot.com/uncanny-x-men-omnibus-2-volume-2/4000-450781/" data-ref-id="4000-450781">The Uncanny X-Men Volume 2</a> #132-141</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-15-la-patrulla-x-hijos/4000-612220/" data-ref-id="4000-612220">Coleccionable Marvel Héroes - La Patrulla-X: Hijos del átomo</a> (#1) (Spanish)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#9) (Spanish)</li><li><a href="https://comicvine.gamespot.com/80-jahre-marvel-3-die-1960er-aufbruch-in-eine-neue/4000-713394/">80 Jahre Marvel - Die 1960er: Aufbruch in eine neue Zeit </a>(#35) (German)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-21-la-patrulla-x-gradu/4000-612226/">Coleccionable Marvel Héroes - La Patrulla-X: Graduación</a> (#56-66) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-56-alpha-flight-de-joh/4000-612264/">Coleccionable Marvel Héroes - Alpha Flight de John Byrne</a> (#120-121 &amp; #139-140) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-4-la-patrulla-x-la-sag/4000-612206/" data-ref-id="4000-612206">Coleccionable Marvel Héroes - La Patrulla-X: La saga de Fénix Oscura</a> (#129-137) (Spanish)</li></ul>', '1963', '141', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/5344/1355017-uxm_v1_001_01.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2136', 'Tip Top Comic Monthly', NULL, '2378', '<p>Published by <a data-ref-id="4010-177" href="/colour-comics-pty-ltd/4010-177/" slug="colour-comics-pty-ltd">  Colour Comics</a> from issues 1 - 98 <br/>Issue 98 - 127 published by <a data-ref-id="4010-176" href="/planet-comics/4010-176/" slug="planet-comics">     Planet Comics</a> <br/> <br/>Title was renamed to <a data-ref-id="4050-27614" href="/batman/4050-27614/" slug="batman">      Batman </a>starting with issue 128</p>', '1965', '127', 'https://comicvine.gamespot.com/a/uploads/scale_medium/3/38919/936587-tip_top_1.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2177', 'Doom Patrol', 'The Trail of the Terrible Titan, A Medal For ''Go-Buggy 3''!', '10', '<p>This series began at #86, with the numbering Continued from: <a href="/my-greatest-adventure/4050-1687/" data-ref-id="4050-1687">My Greatest Adventure</a>. The Doom Patrol consisted of the members, <a href="/robotman/4005-4079/" data-ref-id="4005-4079">Robotman</a>, <a href="/negative-man/4005-4087/" data-ref-id="4005-4087">Negative Man</a>, <a href="/elasti-girl/4005-4088/" data-ref-id="4005-4088">Elasti-Girl</a>, <a href="/mento/4005-14647/" data-ref-id="4005-14647">Mento</a>, <a href="/beast-boy/4005-3586/" data-ref-id="4005-3586">Beast Boy</a>, and the <a href="/the-chief/4005-35126/" data-ref-id="4005-35126">Chief</a>.</p><p>Series was cancelled at #121, (Oct. 1968). A brief three issue reprint revival was published a little over four years later (Feb. 1973) with issues #122-#124.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/doom-patrol-the-silver-age-omnibus/4050-102255/" data-ref-id="4050-102255">Doom Patrol: The Silver Age Omnibus</a> (#86-124)</li><li><a href="/doom-patrol-the-silver-age-1-volume-one/4000-677945/" data-ref-id="4000-677945">Doom Patrol: The Silver Age Volume One</a> (#86-95)</li><li><a href="/doom-patrol-the-silver-age-2-volume-2/4000-743299/" data-ref-id="4000-743299">Doom Patrol: The Silver Age Volume 2</a> (#96-107)</li></ul>', '1964', '39', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/6405-2177-7001-1-doom-patrol-the.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2189', 'The Amazing Spider-Man Annual', 'The Sinister Six!;A Gallery of Spider-Man''s Most Famous Foes!;The Secrets of Spider-Man!;Supporting Cast Pin-Ups;How Stan Lee and Steve Ditko Create Spider-Man!', '31', '<p>Annual volume for <a href="https://comicvine.gamespot.com/the-amazing-spider-man/4050-2127/" data-ref-id="4050-2127">The Amazing Spider-Man Volume 1</a>.</p><p>The original annuals ran for 28 issues before being renamed with unique titles. The series continued numbering with #<strong>1 </strong><em>or </em>35 in 2008.</p><p>In 1995 they did not release an annual, but instead the <a href="../../amazing-spider-man-super-special/49-18772/" rel="nofollow ">Amazing Spider-Man Super Special</a>.</p><p>From 1996-2001 Marvel used a year format with unique titles:</p><ul><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-96/4050-60436/" data-ref-id="4050-60436">The Amazing Spider-Man ''96</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-97/4050-60438/" data-ref-id="4050-60438">The Amazing Spider-Man ''97</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-98/4050-60439/" data-ref-id="4050-60439">Spider-Man ''98</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-99/4050-60440/" data-ref-id="4050-60440">The Amazing Spider-Man 1999</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-2000/4050-60441/" data-ref-id="4050-60441">The Amazing Spider-Man 2000</a></li><li><a href="//www.comicvine.com/the-amazing-spider-man-annual-2001/4050-60442/" data-ref-id="4050-60442">The Amazing Spider-Man 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/the-amazing-spiderman-epic-collection-great-power/4050-77149/" data-ref-id="4050-77149">Amazing Spider-Man Epic Collection: Great Power</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-2-volume/4000-140399/" data-ref-id="4000-140399">Marvel Masterworks: The Amazing Spider-Man Vol. 2</a> (#1)</li><li><a href="https://comicvine.gamespot.com/ditko-is-amazing/4050-123281/">Ditko Is... Amazing!</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/amazing-spiderman-epic-collection-great-responsibi/4050-97134/" data-ref-id="4050-97134">Amazing Spider-Man Epic Collection: Great Responsibility</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-3-volume/4000-140398/" data-ref-id="4000-140398">Marvel Masterworks: The Amazing Spider-Man Vol. 3</a> (#2)</li><li><a href="https://comicvine.gamespot.com/spidermandoctor-strange-the-way-to-dusty-death/4050-102278/" data-ref-id="4050-102278">Spider-Man/Doctor Strange: The Way To Dusty Death</a> (#2 &amp; 14)</li><li><a href="https://comicvine.gamespot.com/decades-marvel-in-the-60s-spider-man-meets-the-mar/4050-117580/">Decades: Marvel In the ''60s: Spider-Man Meets the Marvel Universe</a> (#2-3)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-5-volume/4000-140396/" data-ref-id="4000-140396">Marvel Masterworks: The Amazing Spider-Man Vol. 5</a> (#3)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-spider-man-no-m/4050-110903/">Amazing Spider-Man Epic Collection: Spider-Man No More</a> (#3-4)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-6-volume/4000-140391/" data-ref-id="4000-140391">Marvel Masterworks: The Amazing Spider-Man Vol. 6</a> (#4)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-amazing-spider-man-7-volume/4000-140392/" data-ref-id="4000-140392">Marvel Masterworks: The Amazing Spider-Man Vol. 7</a> (#5)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-the-secret-of-t/4050-124993/">Amazing Spider-Man Epic Collection: The Secret of the Petrified Tablet</a> (#5-6)</li><li