INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2237', 'Sgt. Fury Annual', 'Commission in Korea!', '31', '<p>Series of annuals.</p><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-sgt-fury-2-volume-two/4000-394398/" data-ref-id="4000-394398">Marvel Masterworks: Sgt. Fury, Vol. 2</a> (#1)</li></ul>', '1965', '7', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7493-2237-8257-1-sgt-fury-annual.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2279', 'Teen Titans', 'The Beast-God of Xochatan', '10', '<p><i>The <a href="/teen-titans/4060-19081/" data-ref-id="4060-19081">Teen Titans</a> in their very own series! The sidekicks to the greatest heroes of the DC Universe unite as the Teen Titans--superheroes in their own right out to save the world from threats large and small. Featuring Robin, Kid Flash, Wonder Girl and more!</i></p><p>Starting members: <a href="/dick-grayson/4005-1691/" data-ref-id="4005-1691">Robin</a>, <a href="/wally-west/4005-23879/" data-ref-id="4005-23879">Kid Flash</a>, <a href="/tempest/4005-2382/" data-ref-id="4005-2382">Aqualad</a>, <a href="/donna-troy/4005-4913/" data-ref-id="4005-4913">Wonder Girl</a>. Later constant members: <a href="/roy-harper/4005-3404/" data-ref-id="4005-3404">Speedy</a>, <a href="/lilith-clay/4005-12525/" data-ref-id="4005-12525">Lilith Clay</a>, <a href="/vox/4005-35124/" data-ref-id="4005-35124">Mal Duncan</a>, <a href="/duela-dent/4005-5939/" data-ref-id="4005-5939">Harlequin</a> (Duela Dent).</p><p>Relaunched in <a href="/the-new-teen-titans/4050-3036/" data-ref-id="4050-3036">The New Teen Titans</a> in 1980.</p><h2>Collected Editions</h2><h3>Actual collections:</h3><table data-max-width="true"><thead><tr><th scope="col">Omnibuses</th><th scope="col">Issues</th></tr></thead><tbody><tr><td><a href="/teen-titans-the-silver-age-omnibus-1-vol-1/4000-556462/" data-ref-id="4000-556462">The Silver Age</a></td><td>1-24</td></tr><tr><td><a href="/teen-titans-the-bronze-age-omnibus-1-volume-1/4000-601777/" data-ref-id="4000-601777">The Bronze Age</a></td><td>25-53</td></tr></tbody></table><table data-max-width="true"><thead><tr><th scope="col">TPBs</th><th scope="col">Issues</th></tr></thead><tbody><tr><td><a href="/teen-titans-the-silver-age-1-volume-one/4000-647927/" data-ref-id="4000-647927">The Silver Age, Volume One</a></td><td>1-11</td></tr><tr><td><a href="/teen-titans-the-silver-age-2-volume-two/4000-693449/" data-ref-id="4000-693449">The Silver Age, Volume Two</a></td><td>12-24</td></tr></tbody></table><p>The Bronze Age isn''t collected in TPBs yet. </p><h3>Old collection:</h3><ul><li><a href="/showcase-presents-teen-titans/4050-38657/" data-ref-id="4050-38657">Showcase Presents: Teen Titans, Vol. 1</a> (#1-18)</li><li><a href="/showcase-presents-teen-titans/4050-38657/" data-ref-id="4050-38657">Showcase Presents: Teen Titans, Vol. 2</a> (#19-36)</li></ul><p>Also in <a href="/the-hawk-and-the-dove-the-silver-age/4050-109450/" data-ref-id="4050-109450">The Hawk and the Dove: The Silver Age</a> (#21). </p>', '1966', '53', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7520-2279-8295-1-teen-titans.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2290', 'Fantasy Masterpieces', NULL, '31', '<p>Fantasy Masterpieces reprinted stories Golden Age stories. Originally the books included stories from anthology titles, but with the inclusion of a Captain America reprint in Issue 3 there was an increasing focus on Golden Age super-hero stories. The series continues as <a data-ref-id="4050-2353" href="/marvel-super-heroes-vol-1/4050-2353/" slug="marvel-super-heroes-vol-1">Marvel Super-Heroes Vol.1</a></p>', '1966', '11', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7588-2290-8368-1-fantasy-masterpieces.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2293', 'Marvel Tales', NULL, '31', '<p>The first volume of "Marvel Tales" to be published by Marvel Comics. Numbering continues from <a href="https://comicvine.gamespot.com/marvel-tales-annual-2/4000-119631/" data-ref-id="4000-119631">Marvel Tales Annual #2</a>. The original <a href="/marvel-tales/4050-1283/" data-ref-id="4050-1283">Marvel Tales</a> was published from 1949-1957 by <a href="https://www.comicvine.com/atlas/4010-75/" data-ref-id="4010-75">Atlas</a>.</p><p>This series started out as <a href="https://comicvine.gamespot.com/marvel-tales-annual/4050-131835/" data-ref-id="4050-131835">Marvel Tales Annual</a> in the years 1964 and 1965 before it became a monthly reprint series. Most issues only had reprints in them, but some had additional new stories, such as "Spider-Ham" in 33 issues of the series and "the Freaks" in issue 256.</p><p>The volume''s cover title changed to <em><a href="/marvel-tales-starring-spider-man/4050-138122/" data-ref-id="4050-138122">Marvel Tales Starring Spider-Man</a></em> with issue 122 but the indicia didn''t reflect until issue 223. The title changed again with issue 223 to <a href="/marvel-tales-featuring-spider-man/4050-137722/" data-ref-id="4050-137722"><em>Marvel Tales Featuring Spider-Man</em></a> but the indicia didn''t reflect until issue 239.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/the-marvel-universe-according-to-hembeck/4050-94809/" data-ref-id="4050-94809">The Marvel Universe According To Hembeck</a> (#216-217, 224-226, 235, 248 &amp; 250-252)</li></ul>', '1966', '120', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/7853-2293-8668-1-marvel-tales.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2294', 'Thor', 'Whom the Gods Would Destroy!', '31', '<p>This is continued from <a href="/journey-into-mystery/4050-1497/" data-ref-id="4050-1497">Journey into Mystery (vol. 1)</a>.</p><p>Journey into Mystery volume 1 was a comic that began publication in 1952 by Atlas, and although it wasn''t until the eighty-third issue that <a href="/thor/4005-2268/" data-ref-id="4005-2268">Thor</a> even appeared in comics, let alone the title, it is most often linked to his character. This is why after releasing issue #125 of the series in 1966 that the series changed its name to become the first volume entitled Thor. As of #407, the book was renamed <a href="/the-mighty-thor/4050-61213/" data-ref-id="4050-61213">The Mighty Thor (vol. 1)</a> until #491 when it returned to simply <i>Thor</i>. In 1996, after 502 issues of the series the name changed back to <a href="/journey-into-mystery/4050-7168/" data-ref-id="4050-7168">Journey into Mystery (vol. 3)</a> which is what it was called up until its end in 1998 with issue 521. Although these later Journey into Mystery issues (#503-521) spin out of Thor vol.1, they are not counted in the collective Thor series.</p><p>In 1998, Thor''s adventures restarted with a new number one issue in <a href="/thor/4050-6226/" data-ref-id="4050-6226">Thor (vol. 2)</a> and there they were contained until issue #85 when the series concluded in 2004. After that, Thor disappeared for a couple years until he returned in 2007 for his newest volume, <a href="/thor/4050-18831/" data-ref-id="4050-18831">Thor (vol. 3)</a>, which lasted for twelve issues with its restarted numbering. Marvel then published 599 comics in the collectively-grouped "Thor" series and therefore reverted the numbering back to its original Thor with issue 600. The series again returned to it''s original title name "<a href="/journey-into-mystery/4050-39761/" data-ref-id="4050-39761">Journey Into Mystery</a>" with issue 622. And Thor continued in <a href="/the-mighty-thor/4050-39763/" data-ref-id="4050-39763">The Mighty Thor (vol. 2)</a>. With the events of <a href="/marvel-now/4015-56129/" data-ref-id="4015-56129">Marvel NOW!</a> Thor was once again restarted as <a href="/thor-god-of-thunder/4050-53920/" data-ref-id="4050-53920">Thor: God of Thunder (vol. 1)</a>.</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/marvel-masterworks-the-mighty-thor-4-volume-4/4000-232239/" data-ref-id="4000-232239">Marvel Masterworks: Mighty Thor Vol. 4</a> (#126-130)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-when-titans-clash/4050-95441/" data-ref-id="4050-95441">Thor Epic Collection: When Titans Clash</a> (#126-130)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hercules/4050-36372/">Thor vs. Hercules</a> (#126, 221, 356 &amp; 437)</li><li><a href="https://comicvine.gamespot.com/kirby-is-mighty-king-size/4050-120010/">Kirby Is... Mighty! King-Size</a> (#126, 131-133, 137-139, 160-162 &amp; 167-170)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-mighty-thor-5-volume-5/4000-232946/" data-ref-id="4000-232946">Marvel Masterworks: Mighty Thor Vol. 5</a> (#131-140)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-the-wrath-of-odin/4050-104642/" data-ref-id="4050-104642">Thor Epic Collection: The Wrath of Odin</a> (#131-153)</li><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby </a>(#134-346 &amp; 154-157)</li><li><a href="https://comicvine.gamespot.com/avengers-kang-time-and-time-again/4050-30427/" data-ref-id="4050-30427">Avengers: Kang: Time and Time Again</a> (#140)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-mighty-thor-6-volume-6/4000-233357/" data-ref-id="4000-233357">Marvel Masterworks: Mighty Thor Vol. 6</a> (#141-152)</li><li><a href="https://www.comicvine.com/marvel-masterworks-the-mighty-thor-7-volume