INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2295', 'Thor Annual', 'If Asgard Falls...', '31', '<p>Continued from <a href="../../journey-into-mystery-annual/49-19069/" rel="nofollow ">Journey Into Mystery Annual</a>. Continues as <a href="/the-mighty-thor-annual/4050-79259/" data-ref-id="4050-79259">The Mighty Thor Annual</a> with issue 14. In 1998 three more annuals and a team-up with <a href="/silver-surfer/4005-2502/" data-ref-id="4005-2502">Silver Surfer</a> were released, with unique indicia titles;</p><ul><li><a href="/silver-surfer-thor-annual-98/4050-39906/" data-ref-id="4050-39906">Silver Surfer / Thor ''98</a> (<a href="/silver-surfer-annual/4050-4069/" data-ref-id="4050-4069">Silver Surfer Annual</a>)</li><li><a href="//www.comicvine.com/thor-annual-99/4050-60447/" data-ref-id="4050-60447">Thor 1999</a></li><li><a href="//www.comicvine.com/thor-annual-2000/4050-60449/" data-ref-id="4050-60449">Thor 2000</a></li><li><a href="//www.comicvine.com/thor-annual-2001/4050-60450/" data-ref-id="4050-60450">Thor 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/marvel-masterworks-the-mighty-thor-5-volume-five/4000-232946/" data-ref-id="4000-232946">Marvel Masterworks: The Mighty Thor Volume 5</a> (#2)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-the-wrath-of-odin/4050-104642/" data-ref-id="4050-104642">Thor Epic Collection: The Wrath of Odin</a> (#2)</li><li><a href="https://comicvine.gamespot.com/loki-omnibus/4050-138891/">Loki Omnibus</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-mighty-thor-15-volume-15/4000-520206/" data-ref-id="4000-520206">Marvel Masterworks: The Mighty Thor Volume 15</a> (#5)</li><li><a href="https://comicvine.gamespot.com/thor-vs-hercules/4050-36372/">Thor vs. Hercules</a> (#5)</li><li><a href="https://www.comicvine.com/essential-thor-7-volume-7/4000-429000/" data-ref-id="4000-429000">Essential Thor vol. 7</a> (#5-6)</li><li><a href="/thor-gods-gladiators-and-the-guardians-of-the-gala/4050-65216/" data-ref-id="4050-65216">Thor: Gods, Gladiators and the Guardians of the Galaxy</a> (#5-6)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-mighty-thor-16-volume-16/4000-628586/" data-ref-id="4000-628586">Marvel Masterworks: Mighty Thor Vol. 16</a> (#6)</li><li><a href="https://comicvine.gamespot.com/guardians-of-the-galaxy-tomorrows-heroes-omnibus/4050-116248/">Guardians of the Galaxy: Tomorrow''s Heroes Omnibus</a> (#6)</li><li><a href="https://comicvine.gamespot.com/thor-and-the-eternals-the-celestials-saga/4050-133209/">Thor and the Eternals: The Celestials Saga</a> (#7)</li><li><a href="/marvel-masterworks-the-mighty-thor-18-volume-18/4000-719457/" data-ref-id="4000-719457">Marvel Masterworks: The Mighty Thor Volume 18</a> (#7-8)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-mighty-thor-20-volume-20/4000-845178/" data-ref-id="4000-845178">Marvel Masterworks: The Mighty Thor Volume 20</a> (#9)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-runequest/4050-93027/" data-ref-id="4050-93027">Thor Epic Collection: Runequest</a> (#11)</li><li><a href="https://comicvine.gamespot.com/thor-epic-collection-the-thor-war/4050-132517/">Thor Epic Collection: The Thor War</a> (#16-17)</li></ul>', '1966', '12', 'https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2911493-thoran02.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2330', 'Blue Beetle', 'Bugs the Squids; Who is the Question?', '125', '<p>Starring: <a href="/ted-kord/4005-2054/" data-ref-id="4005-2054">Ted Kord</a> as Blue Beetle (II)</p><p>The opening issues of this short lived series from Charlton Comics featured both Blue Beetle and the Question - two heroes who would leave an indelible impression on the DC Universe for years to come. Eight months after Ted Kord assumed the scarab as Blue Beetle in a back up feature of "Captain Atom" # 83, writer / artist Steve Ditko launched the Beetle into his own series.</p><p>This Beetle didn''t possess super powers. Instead, Kord was a brilliant inventor whose gadgets - chief among them a bug shaped aircraft and a gun that fired blinding light and compressed air blasts - powered his war against crime. In his inaugural issue, the Blue Beetle dispatched the Squids, a costumed gang equipped with suctioning devices that enabled them to climb walls. In the same issue, Ditko introduced Vic Sage, a hard hitting TV reporter for World Wide Broadcasting Company, and his faceless alter ego, the Question, to Hub City''s criminal underground. Using a chemical gas to apply and remove a special skin mask created by his mentor, Aristotle Rodor, Sage was able to conceal his features completely while operating outside of the law.</p><p>As the Question he made his first mark by apprehending gambling ringleader Lou Dicer and his accomplice, WWB executive Jim Lark - on whom Sage blew the whistle during his next broadcast.</p><h4><strong>Notes</strong></h4><ul><li>Fourth Charlton publication; 5th volume overall.</li><li>Unpublished #6 appeared in <a href="https://comicvine.gamespot.com/charlton-portfolio/4050-135701/">Charlton Portfolio</a>.</li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-2030-charlton-heroes-of-the-19/4000-680814/">Charlton Heroes of the 1960s: Volume 2</a> (Question stories from #1-5)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-20252030-charlton-heroes-of-th/4000-683139/">Charlton Heroes of the 1960''s: Volumes 1 &amp; 2</a> (Question stories from #1-5)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-1296-the-complete-question/4000-681014/">The Complete Question</a> (Question stories from #1-5)</li></ul>', '1967', '5', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/8496-2330-9383-1-blue-beetle.jpg', '0');
