INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2350', 'The Avengers Annual', 'The Monstrous Master Plan of the Mandarin', '31', '<p>Avengers annual ran for 23 issues. From 1998-2001 the series ran with a unique indicia titles;</p><ul><li><a href="/avengerssquadron-supreme-98/4050-30632/" data-ref-id="4050-30632">Avengers / Squadron Supreme ''98</a></li><li><a href="/avengers-99/4050-18526/" data-ref-id="4050-18526">Avengers 1999</a></li><li><a href="/avengers-2000/4050-39916/" data-ref-id="4050-39916">Avengers 2000</a></li><li><a href="/avengers-2001/4050-39917/" data-ref-id="4050-39917">Avengers 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="/avengers-omnibus-2-volume-two/4000-482859/" data-ref-id="4000-482859">Avengers Omnibus Volume 2</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/avengers-epic-collection-masters-of-evil/4050-100962/" data-ref-id="4050-100962">Avengers Epic Collection: The Masters of Evil</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-16-volume-16/4000-535357/" data-ref-id="4000-535357">Marvel Masterworks: Avengers Volume 16</a> (#6)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#7)</li><li><a href="https://comicvine.gamespot.com/gamora-guardian-of-the-galaxy/4050-94272/" data-ref-id="4050-94272">Gamora: Guardian of the Galaxy</a> (#7)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-17-volume-17/4000-613795/" data-ref-id="4000-613795">Marvel Masterworks: Avengers Volume 17</a> (#7)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-origin/4050-118000/">The Thanos Wars: Infinity Origin</a> (#7)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-4-volume-4/4000-716964/" data-ref-id="4000-716964">Marvel Masterworks: Marvel Two-In-One Vo