INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2694', 'Marvel Treasury Edition', NULL, '31', '<p>An album-format giant-sized comicbook series.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-team-up-5-volume-5/4000-785731/" data-ref-id="4000-785731">Marvel Masterworks: Marvel Team-Up Volume 5</a> (#9-13)</li><li><a href="/howard-the-duck-the-complete-collection-1-vol-1/4000-493042/" data-ref-id="4000-493042">Howard the Duck: The Complete Collection Vol. 1</a> (#12)</li><li><a href="/marvel-masterworks-howard-the-duck-1-volume-1/4000-828993/" data-ref-id="4000-828993">Marvel Masterworks: Howard the Duck Volume 1</a> (#12)</li><li><a href="/marvel-masterworks-defenders-7-volume-7/4000-814972/" data-ref-id="4000-814972">Marvel Masterworks: Defenders Volume 7</a> (#16)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-the-fate-of-the-phoenix/4050-134230/">X-Men Epic Collection: The Fate of the Phoenix</a> (#26-27)</li></ul>', '1974', '28', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12415-2694-13920-1-marvel-treasury-edit.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2696', 'Marvel Two-in-One', 'Vengeance Of The Molecule Man!', '31', '<p>A series that featured the Fantastic Four''s very own Ben Grimm, better known as the Thing, teaming him up with a multitude of other Marvel Heroes. The series was somewhat of a continuation of Thing''s adventures in <a href="../../marvel-feature/49-2515/" rel="nofollow ">Marvel Feature</a>. After 100 issues of Marvel Two-in-One, the series was replaced by Thing''s own solo series, simply called "<a href="../../the-thing/49-3245/" rel="nofollow ">The Thing</a>".</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/marvel-masterworks-marvel-two-in-one-1-volume-1/4000-433434/" data-ref-id="4000-433434">Marvel Masterworks: Marvel Two-In-One vol. 1</a> (#1-10)</li><li><a href="/man-thing-by-steve-gerber-the-complete-collection-/4000-502866/" data-ref-id="4000-502866">Man-Thing by Steve Gerber: The Complete Collection Vol. 1</a> (#1)</li><li><a href="https://comicvine.gamespot.com/marvel-two-in-one-epic-collection-cry-monster/4050-112694/">Marvel Two-In-One Epic Collection: Cry Monster</a> (#1-19)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-daredevil-11-volume-11/4000-585084/" data-ref-id="4000-585084">Marvel Masterworks: Daredevil Volume 11</a> (#3)</li><li><a href="/guardians-of-the-galaxy-earth-shall-overcome/4050-30359/" data-ref-id="4050-30359">Guardians of the Galaxy: Earth Shall Overcome</a> (#4-5)</li><li><a href="https://comicvine.gamespot.com/guardians-of-the-galaxy-tomorrows-heroes-omnibus/4050-116248/">Guardians of the Galaxy: Tomorrow''s Heroes Omnibus</a> (#4-5, 61-63 &amp; 69)</li><li><a href="/marvel-masterworks-ghost-rider-2-volume-2/4000-821522/" data-ref-id="4000-821522">Marvel Masterworks: Ghost Rider Volume 2</a> (#8)</li><li><a href="https://comicvine.gamespot.com/black-widow-marvel-team-up/4050-125684/">Black Widow: Marvel Team-Up</a> (#10)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#11-20)</li><li><a href="https://comicvine.gamespot.com/marvel-horror-omnibus/4050-121088/">Marvel Horror Omnibus</a> (#11, 18, 33, 41 &amp; 95)</li><li><a href="https://comicvine.gamespot.com/the-son-of-satan-classic/4050-95033/" data-ref-id="4050-95033">The Son of Satan Classic</a> (#14)</li><li><a href="https://comicvine.gamespot.com/morbius-the-living-vampire-omnibus/4050-128226/">Morbius the Living Vampire Omnibus</a> (#15)</li><li><a href="https://comicvine.gamespot.com/morbius-epic-collection-the-end-of-a-living-vampir/4050-136029/">Morbius Epic Collection: The End Of A Living Vampire</a> (#15)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-team-up-5-volume-5/4000-785731/" data-ref-id="4000-785731">Marvel Masterworks: Marvel Team-Up Volume 5</a> (#17)</li><li><a href="https://comicvine.gamespot.com/doctor-strange-lords-of-fear/4050-107359/" data-ref-id="4050-107359">Doctor Strange: Lords of Fear</a> (#18)</li><li><a href="https://comicvine.gamespot.com/tigra-the-complete-collection/4050-123417/">Tigra: The Complete Collection</a> (#19)</li><li><a href="/marvel-masterworks-marvel-two-in-one-3-volume-3/4000-663577/" data-ref-id="4000-663577">Marvel Masterworks: Marvel Two-In-One vol. 3</a> (#21-36)</li><li><a href="/deathlok-the-demolisher-the-complete-collection/4050-77316/" data-ref-id="4050-77316">Deathlok The Demolisher: The Complete Collection</a> (#27 &amp; 54)</li><li><a href="/marvel-masterworks-spider-woman-1-volume-1/4000-505913/" data-ref-id="4000-505913">Marvel Masterworks: Spider-Woman Volume 1</a> (#29-33)</li><li><a href="/skull-the-slayer/4050-81312/" data-ref-id="4050-81312">Skull The Slayer</a> (#35-36)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-4-volume-4/4000-716964/" data-ref-id="4000-716964">Marvel Masterworks: Marvel Two-In-One Volume 4</a> (#37-46)</li><li><a href="/marvel-masterworks-brother-voodoo-1-volume-1/4000-851632/" data-ref-id="4000-851632">Marvel Masterworks: Brother Voodoo Volume 1</a> (#41)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#43, 50 &amp; 53-55)</li><li><a href="/marvel-masterworks-marvel-two-in-one-5-volume-5/4000-819153/" data-ref-id="4000-819153">Marvel Masterworks: Marvel Two-In-One Volume 5</a> (#47-60)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#51)</li><li><a href="https://comicvine.gamespot.com/captain-marvel-ms-marvel-a-hero-is-born/4050-117049/">Captain Marvel: Ms. Marvel: A Hero Is Born</a> (#51)</li><li><a href="https://comicvine.gamespot.com/ms-marvel-epic-collection-the-woman-who-fell-to-ea/4050-118662/">Ms. Marvel Epic Collection: The Woman Who Fell To Earth</a> (#51)</li><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#52)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#52)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#83-84)</li><li><a href="/spider-man-saga-of-the-sandman/4050-27204/" data-ref-id="4050-27204">Spider-Man: Saga of the Sandman</a> (#86)</li><li><a href="/antman-scott-lang/4050-82479/" data-ref-id="4050-82479">Ant-Man: Scott Lang</a> (#87)</li><li><a href="/marvel-masterworks-the-savage-she-hulk-2-volume-2/4000-708135/" data-ref-id="4000-708135">Marvel Masterworks: The Savage She-Hulk Volume 2</a> (#88)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-62-los-4-fantasticos-d/4000-612270/">Coleccionable Marvel Héroes - Los 4 Fantásticos de John Byrne 4</a> (#50) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-76-la-cosa-secret-wars/4000-612314/">Coleccionable Marvel Héroes - La Cosa: Secret Wars</a> (#50 &amp; #100) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#51) (Spanish)</li></ul><p>Issues <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa/4050-41953/" data-ref-id="4050-41953">#1-20 &amp; #22-100</a> have been translated into Spanish.</p>', '1974', '100', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12538-2696-14067-1-marvel-two-in-one.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2697', 'Master of Kung Fu', 'Lair of the Lost!', '31', '<p>Continued from <a href="/special-marvel-edition/4050-2520/" data-ref-id="4050-2520"> Special Marvel Edition</a> #16. In the 1970''s Kung Fu was discovered in America and it became a craze for many years. Enter Shang-Chi, the Master of Kung Fu! After Shang-Chi made his first appearance in Special Marvel Edition issue 15, the series was renamed after the star with issue 17. This stunning and critically acclaimed series lasted for 125 issues, ending in 1983. The series was accompanied by a <a href="https://www.comicvine.com/master-of-kung-fu-annual/4050-28081/">Master of Kung Fu Annual</a> and 4 special <a href="https://www.comicvine.com/giant-size-master-of-kung-fu/4050-2685/">Giant-Size Master of Kung Fu</a> issues. More then 35 years later the series received an <a href="https://comicvine.gamespot.com/master-of-kung-fu/4050-105963/">issue 126</a> published as a one-shot.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-1-volume-1/4000-533502/" data-ref-id="4000-533502">Shang-Chi Master of Kung-Fu Omnibus Volume 1</a> (#17-37)</li><li><a href="/master-of-kung-fu-epic-collection-weapon-of-the-so/4050-109201/" data-ref-id="4050-109201">Master of Kung Fu Epic Collection: Weapon of the Soul</a> (#17-28)</li><li><a href="https://comicvine.gamespot.com/master-of-kung-fu-epic-collection-fight-without-pi/4050-119860/">Master of Kung Fu Epic Collection: Fight Without Pity</a> (#29-53)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-2-volume-2/4000-551546/" data-ref-id="4000-551546">Shang-Chi Master of Kung-Fu Omnibus Volume 2</a> (#38-70)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-3-volume-3/4000-583726/" data-ref-id="4000-583726">Shang-Chi Master of Kung-Fu Omnibus Volume 3</a> (#71-101)</li><li><a href="https://comicvine.gamespot.com/shang-chi-master-of-kung-fu-omnibus-4-volume-4/4000-626294/" data-ref-id="4000-626294">Shang-Chi Master of Kung-Fu Omnibus Volume 4</a> (#102-125)</li></ul><p><strong>Note:</strong> Although the title on the cover always had the extra line; "The Hands of Shang-Chi", the indica just states "Master of Kung Fu".</p>', '1974', '109', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12660-2697-14204-1-master-of-kung-fu.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2700', 'Power Man', 'Rich man: Iron Man -- Power Man: Thief!', '31', '<p>This series is continued from <a href="/hero-for-hire/4050-2572/" data-ref-id="4050-2572">Hero for Hire </a>issue 16 when it changed its name to Power Man with issue 17. Luke Cage fights criminals in the mean streets of New York City. See how this former Hero for Hire becomes an icon for the regular people. The series continues as <a href="/power-man-and-iron-fist/4050-2959/" data-ref-id="4050-2959">Power Man &amp; Iron Fist </a>with issue 50 and on.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-luke-cage-power-man-1-volume-2/4000-619633/" data-ref-id="4000-619633">Marvel Masterworks: Luke Cage, Power Man Volume 2</a> (#17-31)</li><li><a href="https://comicvine.gamespot.com/luke-cage-epic-collection-retribution/4050-133628/">Luke Cage Epic Collection: Retribution</a> (#17-23)</li><li><a href="/marvel-masterworks-ant-mangiant-man-3-volume-3/4000-673021/" data-ref-id="4000-673021">Marvel Masterworks: Ant-Man/Giant-Man Volume 3</a> (#24-25)</li><li><a href="/power-man-and-iron-fist-epic-collection-heroes-for/4050-83705/" data-ref-id="4050-83705">Power Man and Iron Fist Epic Collection: Heroes For Hire</a> (#48-49)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-1-hc/4000-523259/" data-ref-id="4000-523259">Marvel Universe by John Byrne Omnibus Volume 1</a> (#48-50)</li></ul>', '1974', '33', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/12541-2700-14070-1-power-man.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2702', 'Spidey Super Stories', 'Spider-Man Is Born!', '31', '<p>This volume was based on the Spiderman segments from the "Electric Company" television program. </p>', '1974', '57', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13104-2702-14686-1-spidey-super-stories.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2730', 'DC Special', 'Super-Heroes Battle Super-Gorillas', '10', '<p>Continues the numbering from the original <em><a href="https://comicvine.gamespot.com/dc-special/4050-2392/" data-ref-id="4050-2392">DC Special</a>.</em></p><h4>Collected Editions</h4><ul><li><a href="/justice-league-of-america-the-bronze-age-omnibus-3/4000-867809/" data-ref-id="4000-867809">Justice League of America: The Bronze Age Omnibus Volume 3</a> (#27)</li></ul>', '1975', '14', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/3125/354294-2730-127310-1-dc-special.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2733', 'The Joker', 'The Joker''s Double Jeopardy', '10', '<p>In 1975 the Clown Prince Of Crime became the very first villain to gain his own ongoing series. "The Joker" lasted only 9 issues, focused on the Rollicking Rogue''s various misadventures and criminal endeavors. Each issue saw The Joker face not only heroes but fellow villains as well. Decades later the unpublished tenth issue was finally published as a digital exclusive release.</p><h4>Collected Editions</h4><ul><li><a href="//www.comicvine.com/the-joker-the-clown-prince-of-crime/4050-69566/" data-ref-id="4050-69566">The Joker: The Clown Prince of Crime</a></li><li><a href="https://comicvine.gamespot.com/the-joker-the-bronze-age-omnibus/4050-120647/">The Joker: The Bronze Age Omnibus</a> (#1-10)</li></ul>', '1975', '10', 'https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/7091420-01.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2737', 'Richard Dragon, Kung Fu Fighter', 'Coming of a Dragon', '10', '<p>In the mid 1970''s Kung Fu was popular in TV and films and so DC got on board with this martial arts series. Richard Dragon Kung Fu Fighter lasted a reasonable 18 issues before being beaten by the DC Implosion, which claimed 31 titles in the late 1970''s.</p><p>Collected in <a href="https://comicvine.gamespot.com/richard-dragon-kung-fu-fighter-coming-of-the-drago/4050-133796/">Richard Dragon, Kung-Fu Fighter: Coming of the Dragon!</a>.</p>', '1975', '18', 'https://comicvine.gamespot.com/a/uploads/scale_medium/1/14065/282662-2737-121664-1-richard-dragon-kung.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2741', 'Super-Team Family', 'The Superman-Batman Revenge Squads, Stepping Stones For A Giant Killer, Mystery of the Elongated Man!', '10', '<p>Unlike other DC Family titles, this ongoing started out almost exclusively as a reprint book, featuring stories from <a href="/golden-age-of-comics/4015-55820/" data-ref-id="4015-55820">Golden</a> and <a href="/silver-age-of-comics/4015-55821/" data-ref-id="4015-55821">Silver Age</a> titles such as <a href="/worlds-finest-comics/4050-18006/" data-ref-id="4050-18006">World''s Finest v1</a> and <a href="/all-star-comics/4050-2833/" data-ref-id="4050-2833">All-Star Comics v1</a>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/justice-league-of-america-the-wedding-of-the-atom-/4050-124796/">Justice League of America: The Wedding of the Atom and Jean Loring</a> (#11-14)</li><li><a href="/justice-league-of-america-the-bronze-age-omnibus-3/4000-867809/" data-ref-id="4000-867809">Justice League of America: The Bronze Age Omnibus Volume 3</a> (#11-14)</li><li><a href="https://comicvine.gamespot.com/new-gods-by-gerry-conway/4050-126349/">New Gods by Gerry Conway</a> (#15)</li></ul>', '1975', '15', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/14049-2741-15725-1-super-team-family.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2746', 'The Champions', 'The World Still Needs... The Champions!', '31', '<p>A new superhero team for the common man! The short-lived, but legendary superhero team known as the Champions, starring a variety of superheroes such as Hercules, Ghost Rider, Iceman, Angel, Dark Star and the Black Widow! The series lasted for only 17 issues. The round-up to the Champions'' story was in Spectacular Spider-Man<a href="https://www.comicvine.com/the-spectacular-spider-man-17-whatever-happened-to/4000-18429/"> issue 17</a> and <a href="https://www.comicvine.com/the-spectacular-spider-man-18-my-friend-my-foe/4000-18511/">issue 18</a>.</p><h4>Collected Editions</h4><ul><li><a href="/champions-classic-1-volume-one/4000-140344/" data-ref-id="4000-140344">The Champions Classic Vol. 1</a> (#1-11)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#1-17)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#1-17)</li><li><a href="https://comicvine.gamespot.com/the-champions-no-time-for-losers/4050-95208/" data-ref-id="4050-95208">The Champions: No Time For Losers</a> (#1-3 &amp; 14-15)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-1-hc/4000-523259/" data-ref-id="4000-523259">Marvel Universe by John Byrne Omnibus Volume 1</a> (#11-15)</li><li><a href="/marvel-masterworks-ant-mangiant-man-3-volume-3/4000-673021/" data-ref-id="4000-673021">Marvel Masterworks: Ant-Man/Giant-Man Volume 3</a> (#11-13)</li><li><a href="/champions-classic-2-volume-two/4000-140345/" data-ref-id="4000-140345">The Champions Classic Vol. 2</a> (#12-17)</li><li><a href="/super-villains-unite-the-complete-supervillain-tea/4050-80542/" data-ref-id="4050-80542">Super Villains Unite: The Complete Super-Villain Team-Up</a> (#16)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#17)</li></ul>', '1975', '17', 'https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/4018334-tn1.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2759', 'Giant-Size Marvel Triple Action', 'Never Bug a Giant!', '31', NULL, '1975', '2', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13543-2759-15182-1-giant-size-marvel-tr.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2761', 'Giant-Size Super-Villain Team-Up', 'Encounter at Land''s End!', '31', '<p>A two-part story showing Dr. Doom''s and Submariner''s struggle to form an alliance to rule the world.</p><p>These where specials to the monthly <a href="/super-villain-team-up/4050-2782/" data-ref-id="4050-2782">Super-Villain Team-Up</a> series.</p><p>Collected in <a href="/super-villains-unite-the-complete-supervillain-tea/4050-80542/" data-ref-id="4050-80542">Super Villains Unite: The Complete Super-Villain Team-Up</a>.</p>', '1975', '2', 'https://comicvine.gamespot.com/a/uploads/scale_medium/6/67663/4427950-01.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2763', 'Giant-Size X-Men', 'Deadly Genesis!; Call Him...Cyclops; I, the Iceman; The Female of the Species!', '31', '<p>The series that famously introduced the New X-men team in 1975. It was a companion title to the (Uncanny) X-Men series and featured the first original X-Men-story in 5 years. After issue 1 of this series, the X-Men returned in full force in <a href="https://comicvine.gamespot.com/the-x-men-94-the-doomsmith-scenario/4000-15508/">(Uncanny) X-men issue 94</a>.</p><h4>Collected Editions</h4><ul><li><a href="/giantsize-xmen-40th-anniversary/4050-82296/" data-ref-id="4050-82296">Giant-Size X-Men: 40th Anniversary</a> (#1 &amp; 3-4)</li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#1)</li><li><a href="https://comicvine.gamespot.com/x-men-we-are-the-x-men/4050-35334/">X-Men: We Are the X-Men</a> (#1)</li><li><a href="https://comicvine.gamespot.com/giant-size-x-men-tribute-to-wein-and-cockrum-galle/4050-137986/">Giant-Size X-Men: Tribute To Wein &amp; Cockrum Gallery Edition</a> (#1)</li><li><a href="https://comicvine.gamespot.com/astonishing-x-men-companion/4050-126608/">Astonishing X-Men Companion</a> (#3-4)</li></ul>', '1975', '4', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13286-2763-14890-1-giant-size-x-men.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2764', 'The Inhumans', 'Spawn of Alien Heat', '31', '<p>From the pages of the Fantastic Four come the Inhumans in their own series! The most uncanny heroes of all! The race known as the Inhumans star in their first own ongoing series. It was a bi-monthly series that lasted for 12 issues.</p><p>Issue <a href="https://comicvine.gamespot.com/biblioteca-marvel-hulk-27/4000-285416/" data-ref-id="4000-285416">#12</a> has been translated into Spanish.</p>', '1975', '12', 'https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/3542293-inhumans1nm9m103.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2765', 'The Invaders', 'Battle over Britain!', '31', '<p><b>The Invaders Volume 1.</b></p><p>Marvel''s redefinition of the heroes from World War Two! Join Captain America, Namor, Bucky, the original Human Torch, Union Jack and Spitfire among others while they fight the axis of evil, such as the Nazi''s and the Japanese.</p><h4>Collected Editions</h4><ul><li>Invaders Classic Vol. 1 (1-9), Vol. 2 (10-21), Vol. 3 (22-23, 25-34), Vol. 4 (35-41)</li><li><a href="https://www.comicvine.com/the-invaders-classic-the-complete-collection-1-vol/4000-456284/" data-ref-id="4000-456284">The Invaders Classic: The Complete Collection Vol. 1</a> (#1-22)</li><li><a href="https://www.comicvine.com/the-invaders-classic-the-complete-collection-2-vol/4000-472288/" data-ref-id="4000-472288">The Invaders Classic: The Complete Collection Vol. 2</a> (#23-41)</li></ul>', '1975', '41', 'https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2697107-invaders01.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2766', 'Iron Fist', 'A Duel of Iron!', '31', '<p>The first volume starring Iron Fist in his own ongoing series. The series is perhaps well known for introducing X-men enemy Sabretooth as well as John Byrne''s first X-men work in issue 15 of this series. The series was canceled after issue 15, but not a few month later, Iron Fist got a starring role in the Power Man series, witch became <a href="../../power-man-and-iron-fist/49-2959/" rel="nofollow "> Power Man and Iron Fist</a> after he joined the cast.</p><h4>Collected Editions</h4><ul><li><a href="/iron-fist-epic-collection-the-fury-of-iron-fist/4050-83138/" data-ref-id="4050-83138">Iron Fist Epic Collection: The Fury of Iron Fist</a></li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a></li><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#14-15)</li></ul>', '1975', '15', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/14106-2766-15784-1-iron-fist.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2782', 'Super-Villain Team-Up', 'Slayers From the Sea!', '31', '<p>Most of the series starred Dr. Doom teaming up with Namor, the Sub-Mariner, whom the Latverian monarch had bent to his service with promises of assistance for ailing Atlantean people. Von Doom''s schemes brought him into conflict with several of Namor''s foes, including the Tiger Shark and Attuma, but the Avengers, Circus of Crime, the debut of the Shroud, and the Red Skull also appeared to complicate Von Doom''s megalomaniac plans for world domination. In later issues of the series, Von Doom and Magneto became embroiled in a bitter rivalry that led both into conflict with both the Avengers and the Champions of Los Angeles. The last issues of the series focused on the Red Skull''s efforts to recreate the Cosmic Cube with the help of the original Hate-Monger and Arnim Zola.</p><p>The series had two special <a href="/giant-size-super-villain-team-up/4050-2761/" data-ref-id="4050-2761">Giant-Size Super-Villain Team-Up </a>issues.</p><p>The title has been appropriated by comic book fans Chris Stewart and Rob Pickering for their Tumblr podcast, which they indicate is strictly for parody. <em>Super-Villain Team-Up </em>began in 2012, featuring the original <a href="//www.comicvine.com/porcupine/4005-12610/" data-ref-id="4005-12610">Porcupine</a> and the first <a href="//www.comicvine.com/eel-stryke/4005-10312/" data-ref-id="4005-10312">Eel</a> interviewing low tier Marvel super-villains to pay back the <a href="//www.comicvine.com/tinkerer/4005-3144/" data-ref-id="4005-3144">Tinkerer</a> for services rendered. Stewart and Pickering''s use of two inactive characters is apparently a dig at the frequent resurrections that occur in comics.</p><h4>Collected Editions</h4><ul><li><a href="/super-villains-unite-the-complete-supervillain-tea/4050-80542/" data-ref-id="4050-80542">Super Villains Unite: The Complete Super-Villain Team-Up</a> (#1-14 &amp; #16-17)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-16-volume-16/4000-535357/" data-ref-id="4000-535357">Marvel Masterworks: Avengers Volume 16</a> (#9)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#14)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#14)</li></ul>', '1975', '17', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/13839-2782-15501-1-super-villain-team-u.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2789', 'Super Adventure Album', NULL, '2378', '<p>Published by <a data-ref-id="4010-2378" href="/murray-comics/4010-2378/" slug="murray-comics">   Murray Comics</a> starting at <a data-ref-id="4050-28259" href="/super-adventure-album/4050-28259/" slug="super-adventure-album"> issue #13</a>.</p>', '1976', '14', 'https://comicvine.gamespot.com/a/uploads/scale_medium/3/38919/976086-saa_1.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2836', 'DC Super Stars', 'Teen Titans: Monster Bait;  Skis of Death', '10', '<p>Eighteen issue series.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/deadman-omnibus/4050-132454/">Deadman Omnibus</a> (#18)</li></ul>', '1976', '18', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/14424-2836-16130-1-dc-super-stars.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2839', 'Green Lantern', 'The Planet of Doomed Men; Menace of the Giant Puppet!', '10', '<figure data-align="right" data-size="medium" data-img-src="https://static.comicvine.com/uploads/original/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg" data-ref-id="1300-4187013" data-ratio="1.4911463187325" data-width="1073" data-embed-type="image" style="width: 1073px"><a class="fluid-height" style="padding-bottom:149.1%" href="https://static.comicvine.com/uploads/original/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg" data-ref-id="1300-4187013"><img alt="Promo by Dave Gibbons" src="https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg 1073w, https://comicvine.gamespot.com/a/uploads/scale_super/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg 960w, https://comicvine.gamespot.com/a/uploads/scale_medium/14/148518/4187013-1983%20-%20green%20lantern%20house%20ad%20%282%29.jpg 643w" sizes="(max-width: 643px) 100vw, 643px" data-width="643"></a><figcaption>Promo by Dave Gibbons</figcaption></figure><p>Preceded by <a href="https://comicvine.gamespot.com/green-lantern/4050-25944/" data-ref-id="4050-25944">Volume 1</a>.</p><p>Continued in <a href="https://comicvine.gamespot.com/the-green-lantern-corps/4050-3600/" data-ref-id="4050-3600">Green Lantern Corps Volume 1</a>.</p><p><ins><a href="/green-lantern/4050-25944/" data-ref-id="4050-25944">Volume 1</a></ins> was centered around <a href="/alan-scott/4005-12663/" data-ref-id="4005-12663">Alan Scott</a>. Although the volumes share the names the Green Lanterns had completely different powers and origins.</p><p><ins>Volume 2</ins> featured <a href="/hal-jordan/4005-11202/" data-ref-id="4005-11202">Hal Jordan</a>. He debuted in Showcase #22 in 1959. This series would include the first appearances of <a href="/sinestro/4005-10448/" data-ref-id="4005-10448">Sinestro</a>, <a href="/guy-gardner/4005-1791/" data-ref-id="4005-1791">Guy Gardner</a>, and <a href="/john-stewart/4005-10451/" data-ref-id="4005-10451">John Stewart</a>. For several years during the middle of this volume''s publication, <a href="/green-arrow/4005-5936/" data-ref-id="4005-5936">Green Arrow</a> would be given a co-starring role and cover credit (issues #76- 122). The series then changed its cover title back to <em>Green Lantern</em>, which lasted up to issue #200. Then the series changed its cover title again to<em> Green Lantern Corps</em>, which lasted five issue before the series became officially<em> <a href="/the-green-lantern-corps/4050-3600/" data-ref-id="4050-3600">Green Lantern Corps</a></em> beginning with issue #206.</p><h4>Writers</h4><ul><li><a href="/john-broome/4040-48152/" data-ref-id="4040-48152">John Broome</a> #1-16, 18-22, 24, 27, 29-31, 39-40, 44-47, 49-55, 59, 66, 69-71, 75, 87-89, 184</li><li><a href="/gardner-fox/4040-41171/" data-ref-id="4040-41171">Gardner Fox</a> #16-17, 21-23, 25-29, 32-38, 41-44, 46, 48, 50, 56-58, 60, 62, 65, 67</li><li>Mike Friedrich #61, 73-74</li><li><a href="/dennis-oneil/4040-40861/" data-ref-id="4040-40861">Dennis O''Neil</a> #63-64, 68, 72, 76-87, 89-100, 102-106, 108-129</li><li><a href="/elliot-s-maggin/4040-42850/" data-ref-id="4040-42850">Elliot S! Maggin</a> #87, 100</li><li>Frank McGinty #101</li><li>Bob Rozakis #107, 130, 159-160</li><li>Cary Burkett #107-110</li><li><a href="/len-wein/4040-41457/" data-ref-id="4040-41457">Len Wein</a> #128, 172-183, 185-186</li><li>Bob Toomey #130-132</li><li>Mike W. Barr #131, 154, 156-165</li><li>Paul Kupperberg #132, 148-149, 151-158, 181, 187</li><li>Jack C. Harris #132, 168-169</li><li><a href="/marv-wolfman/4040-41478/" data-ref-id="4040-41478">Marv Wolfman</a> #133-153</li><li>Laurie Sutton #133-147 (Adam Strange features)</li><li>Roy Thomas #138-139</li><li>Dan Mishkin #152-153</li><li>Gary Cohn #152-153, 170</li><li>Robin Snyder #161, 171</li><li><a href="/kurt-busiek/4040-41741/" data-ref-id="4040-41741">Kurt Busiek</a> #162, 185</li><li>Todd Klein #162-167, 171-172, 179-180, 189-190</li><li><a href="/joey-cavalieri/4040-41787/" data-ref-id="4040-41787">Joey Cavalieri</a> #166-169, 171, 173, 182-183</li><li><a href="/keith-giffen/4040-6536/" data-ref-id="4040-6536">Keith Giffen</a> #171</li><li>Mike Baron #187</li><li><a href="/alan-moore/4040-40382/" data-ref-id="4040-40382">Alan Moore</a> #188 (back-up story)</li><li><a href="/steve-englehart/4040-42211/" data-ref-id="4040-42211">Steve Englehart</a> #188-205</li></ul><h2>Collected Editions</h2><h3>The Silver Age</h3><p>Actual collection</p><table data-max-width="true"><thead><tr><th scope="col">TP</th><th scope="col">Issues</th><th scope="col">Omnibus</th><th scope="col">Issues</th></tr></thead><tbody><tr><td><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-1-volume-one/4000-552137/" data-ref-id="4000-552137">Vol. 1</a></td><td>1-9</td><td><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-omnibus-1-volume-1/4000-582499/" data-ref-id="4000-582499">Vol. 1</a></td><td>1-35</td></tr><tr><td><a href="https://comicvine.gamespot.com/green-lantern-the-silver-age-2-volume-two/4000-636344/" data-ref-id="4000-636344">Vol. 2</a></td><td>10-22</td><td> </td><td> </td></tr><tr><td><a href="/green-lantern-the-silver-age-3-volume-three/4000-666782/" data-ref-id="4000-666782">Vol. 3</a></td><td>23-35</td><td> </td><td> </td></tr><tr><td><a href="/green-lantern-the-silver-age-4-volume-four/4000-720046/" data-ref-id="4000-720046">Vol. 4</a></td><td>36-48</td><td><a href="/green-lantern-the-silver-age-omnibus-2-volume-2/4000-664265/" data-ref-id="4000-664265">Vol. 2</a></td><td>36-75</td></tr></tbody></table><h4>Archives</h4><ul><li><a href="/green-lantern-archives-/4000-214818/" data-ref-id="4000-214818">Green Lantern Archives Vol. 1</a> (#1-5)</li><li><a href="/green-lantern-archives-/4000-214819/" data-ref-id="4000-214819">Green Lantern Archives Vol. 2</a> (#6-13)</li><li><a href="/green-lantern-archives-/4000-214820/" data-ref-id="4000-214820">Green Lantern Archives Vol. 3</a> (#14-21)</li><li><a href="/green-lantern-archives-volume-four/4000-214821/" data-ref-id="4000-214821">Green Lantern Archives Vol. 4</a> (#22-29)</li><li><a href="/green-lantern-archives-/4000-214822/" data-ref-id="4000-214822">Green Lantern Archives Vol. 5</a> (#30-38)</li><li><a href="/green-lantern-archives-/4000-214823/" data-ref-id="4000-214823">Green Lantern Archives Vol. 6</a> (#39-47)</li><li><a href="/green-lantern-archives-volume-7/4000-373985/" data-ref-id="4000-373985">Green Lantern Archives Vol. 7</a> (#48-57)</li></ul><h4>Showcase Presents</h4><ul><li><a href="/showcase-presents-green-lantern-volume-one/4000-214824/" data-ref-id="4000-214824">Showcase Presents: Green Lantern Vol. 1</a> (#1-17)</li><li><a href="/showcase-presents-green-lantern-/4000-214825/" data-ref-id="4000-214825">Showcase Presents: Green Lantern Vol. 2</a> (#18-38)</li><li><a href="/showcase-presents-green-lantern-3-volume-three/4000-214826/" data-ref-id="4000-214826">Showcase Presents: Green Lantern Vol. 3</a> (#39-59)</li><li><a href="/showcase-presents-green-lantern-4-volume-four/4000-225810/" data-ref-id="4000-225810">Showcase Presents: Green Lantern Vol. 4</a> (#60-75)</li><li><a href="/showcase-presents-green-lantern-5-vol-five/4000-269622/" data-ref-id="4000-269622">Showcase Presents: Green Lantern Vol. 5</a> (#76-89)</li></ul><h4>Green Lantern/Green Arrow</h4><ul><li><a href="/green-lantern-green-arrow-1-volume-1/4000-395528/" data-ref-id="4000-395528">Green Lantern/Green Arrow Vol. 1</a> (#76-82)</li><li><a href="https://comicvine.gamespot.com/green-lantern-green-arrow-2-volume-2/4000-395529/" data-ref-id="4000-395529">Green Lantern/Green Arrow Vol. 2</a> (#83-87, 89)</li><li>Green Lantern/Green Arrow: Hard-Traveling Heroes Omnibus (#76-87, 89-123)</li></ul><h4>Omnibus</h4><ul><li><a href="/green-lantern-omnibus-volume-one/4000-255587/" data-ref-id="4000-255587">Green Lantern Omnibus Vol. 1</a> (#1-21)</li><li><a href="/green-lantern-omnibus-green-lantern-omnibus-vol-2/4000-303545/" data-ref-id="4000-303545">Green Lantern Omnibus Vol. 2</a> (#22-45)</li><li><a href="/green-lantern-the-silver-age-omnibus-1-volume-1/4000-582499/" data-ref-id="4000-582499">Green Lantern: The Silver Age Omnibus #1 - Volume 1</a> (#1-35)</li><li><a href="/green-lantern-the-silver-age-omnibus-2-volume-2/4000-664265/" data-ref-id="4000-664265">Green Lantern: The Silver Age Omnibus #2 - Volume 2</a> (#36-75)</li></ul><h4>Green Lantern Chronicles</h4><ul><li><a href="/green-lantern-chronicles-vol-1/4000-255584/" data-ref-id="4000-255584">Vol. 1</a> (#1-3)</li><li><a href="/green-lantern-chronicles-vol-2/4000-255585/" data-ref-id="4000-255585">Vol. 2</a> (#4-9)</li><li><a href="/green-lantern-chronicles-vol-3/4000-255586/" data-ref-id="4000-255586">Vol. 3</a> (#10-14)</li><li><a href="/green-lantern-chronicles-vol-4/4000-322766/" data-ref-id="4000-322766">Vol. 4</a> (#15-20)</li></ul><h4>Sector 2814</h4><ul><li><a href="https://www.comicvine.com/green-lantern-sector-2814-1-volume-1/4000-382107/">Vol. 1</a> (#172-176 and 178-181)</li><li><a href="https://www.comicvine.com/green-lantern-sector-2814-2-volume-2/4000-422853/">Vol. 2</a> (#182-183 and 185-193)</li><li><a href="https://www.comicvine.com/green-lantern-sector-2814-3-volume-3/4000-441862/">Vol. 3</a> (#194-200)</li></ul><h4>Other Collections</h4><ul><li><a href="/green-lantern-the-greatest-stories-ever-told/4050-38193/" data-ref-id="4050-38193">Green Lantern: The Greatest Stories Ever Told</a> (#1, 31, 74, 87, 172)</li><li><a href="https://comicvine.gamespot.com/green-lantern-john-stewart-a-celebration-of-50-yea/4050-137003/">Green Lantern John Stewart: A Celebration of 50 Years</a> (#87, 182 &amp; 185)</li><li><a href="https://comicvine.gamespot.com/green-lanterngreen-arrow-space-traveling-heroes/4050-128829/">Green Lantern/Green Arrow: Space Traveling Heroes</a> (#90-106)</li><li><a href="/crisis-on-infinite-earths-companion-deluxe-edition/4000-691351/" data-ref-id="4000-691351">Crisis On Infinite Earths Companion Deluxe Edition Volume 1</a> (#194-198)</li><li><a href="/absolute-green-lanterngreen-arrow/4050-86762/" data-ref-id="4050-86762">Absolute Green Lantern/Green Arrow</a> (#76-87 &amp; 89)</li></ul>', '1960', '205', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/4457-2013-4869-1-green-lantern.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2847', 'Super Friends', 'The Fury of the Super Foes', '10', '<p>Since 1973, Alex Toth''s rendering of the JLA had dominated Saturday morning television. In fact, Hanna-Barbera''s animated "Super Friends" proved so successful that DC brought the concept full circle, adapting the show into a comic. Scribe E. Nelson Bridwell and artist Ric Estrada crafted the inaugural issue, pitting "the most powerful forces of good ever assembled" against a band of self-proclaimed, "Super Foes." Although not considered DC canon, "Super Friends" enjoyed nearly a five year run in comics form, lasting for 47 issues.</p><p>The team started as Superman, Wonder Woman, Batman and Robin, Aquaman, Wendy, Marvin and Wonder Dog. There was a storyline in issue 7 which lasted 3 issues where the Wonder Twins (Zan, Jayna, Gleek) came to Earth to warn Earth''s heroes of an impending threat by the name of Grax. This storyline included the entire Justice League and the Global Guardians. At the end of the story (Issue 9) Wendy and Marvin had captured Grax and The Super Friends said that they completed their training and were ready to become full fledged super heroes. Both kids said they were going to college and Zan and Jayna asked if the Super Friends would train them and they agreed. Many issues had morals for the Wonder Twins to learn. Issue 10 showed us that an old friend of Superman and Batman, Professor Carter Nicholls agreed to be the Guardian of Zan and Jayna and he came up with alter egos and a European Country that they came from. Also we met a group of alien heroes who tracked a beautiful woman to earth. The twins learned a valuable lesson that the monsters were the heroes and the beauty was the evil one.</p><p>Many heroes guest starred as well as supporting characters from the Super Friends individual books. Solovar and King Vulko were in issue 11 and the SF battled the Kingslayer. In issue 12 TNT and Dynamite guest starred and their were brief visits to Atlantis and the Bottled City of Kandor. Several villains such as Grax, Overlord, and Menagerie Man made multiple appearances. The Super Friends also battled villains from other heroes'' Rogues Gallery such as : (Mirror Master-23 )Flash Villain, Flash Villain (Weather Wizard-37), Atom Villain (Chronos-22), WW and Flash villains(Giganta and Grodd-30). Many other guest stars included Mera and Aqualad (issues 25 and 27), Jimmy Olsen (28), Black Orchid (31), Scarecrow (32), Hawkman (33), Plastic Man (36), Supergirl (37), Topo (38), Green Fury (42-44, 47) and the Global Guardians (45-46).</p><p>When DC expanded their books to 25 pages, in SF there were rotating solo stories beginning with issue 35. The Wonder Twins, Jack O Lantern, and the Seraph rotated solo back-up stories with Plastic Man joining the rotation in issues 44 and 46. Issue 47 ended the run with a full length adventure guest starring the Green Fury and a trip to Brazil, ending in a death of someone the Green Fury new. The Super Friends went to Exxor in issues 21 and 46 and to Atlantis in issue 27 and Gorilla City in Issue 30. All in all it was a very fun run. The JLA Satellite was used several times (2, 3 7-9,16) and old JLA villains made appearances.</p><p>Felix Faust (28), Kanjar Ro, Queen Bee (45-46) along with Sinestro, Hector Hammond and World Beater (45-46)</p><h4>Collected Editions</h4><ul><li><a href="https://www.comicvine.com/showcase-presents-super-friends-1-volume-1/4000-453402/" data-ref-id="4000-453402">Showcase Presents: Super Friends vol. 1</a> (#1-35)</li><li><a href="/the-super-friends-saturday-morning-comics-1-volume/4000-767290/" data-ref-id="4000-767290">The Super Friends Saturday Morning Comics Volume One</a> (#1-26)</li><li><a href="/the-super-friends-saturday-morning-comics-2-volume/4000-821731/" data-ref-id="4000-821731">The Super Friends Saturday Morning Comics Volume Two</a> (#27-47)</li><li><a href="https://comicvine.gamespot.com/dc-through-the-80s-the-end-of-eras/4050-132564/">DC Through the ''80s: The End of Eras</a> (#36)</li></ul>', '1976', '47', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/15102-2847-16844-1-super-friends.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2858', 'The Eternals', 'The Day of the Gods', '31', '<p>The first Eternals series, created and drawn by Jack "King" Kirby.</p><h4>Collected Editions</h4><ul><li><a href="/kingsize-kirby/4050-83141/" data-ref-id="4050-83141">King-Size Kirby</a> (#7)</li><li><a href="https://comicvine.gamespot.com/the-eternals-by-jack-kirby-the-complete-collection/4050-128818/">The Eternals by Jack Kirby: The Complete Collection</a> (#1-19)</li><li><p><a href="https://comicvine.gamespot.com/the-eternals-the-complete-saga-omnibus/4050-132398/">The Eternals: The Complete Saga Omnibus</a> (#1-19)</p></li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/kingsize-kirby/4050-104017/">King-Size Kirby</a> (#7) (Spanish)</li></ul>', '1976', '19', 'https://comicvine.gamespot.com/a/uploads/scale_medium/8/84205/3542334-eternals1nm92m112.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2860', 'The Incredible Hulk Annual', 'A Refuge Divided!', '31', '<p>Although there were twenty numbered annuals, from 1997-1994, five more annuals and 1 team-up with <a href="/x-man/4005-15051/" data-ref-id="4005-15051">X-Man</a> were released, with unique titles;</p><ul><li><a href="//www.comicvine.com/the-incredible-hulk-annual-97/4050-60432/" data-ref-id="4050-60432">The Incredible Hulk ''97</a></li><li><a href="//www.comicvine.com/the-incredible-hulk-and-sub-mariner-annual-98/4050-60434/" data-ref-id="4050-60434">Hulk / Sub-Mariner ''98</a></li><li><a href="/x-man-hulk-annual-98/4050-28192/" data-ref-id="4050-28192">X-Man / Hulk ''98</a> (<a href="/x-man-annual-96/4050-18050/" data-ref-id="4050-18050">X-Man Annual</a>)</li><li><a href="//www.comicvine.com/hulk-annual-1999/4050-58522/" data-ref-id="4050-58522">Hulk 1999</a></li><li><a href="//www.comicvine.com/the-incredible-hulk-annual-2000/4050-60435/" data-ref-id="4050-60435">Hulk 2000</a></li><li><a href="/incredible-hulk-annual-2001/4050-39930/" data-ref-id="4050-39930">Incredible Hulk 2001</a></li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/inhumans-beware-the-inhumans/4050-107505/" data-ref-id="4050-107505">Inhumans: Beware the Inhumans</a> (#1)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-the-leader-lives/4050-114890/">Incredible Hulk Epic Collection: The Leader Lives</a> (#1)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#5)</li><li><a href="/marvel-masterworks-the-incredible-hulk-13-volume-1/4000-718774/" data-ref-id="4000-718774">Marvel Masterworks: The Incredible Hulk Volume 13</a> (#6)</li><li><a href="https://www.comicvine.com/xmen-vs-hulk/4050-73770/" data-ref-id="4050-73770">X-Men Vs Hulk</a> (#7)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#7)</li><li><a href="/marvel-universe-by-john-byrne-omnibus-2-volume-2/4000-694138/" data-ref-id="4000-694138">Marvel Universe by John Byrne Omnibus Volume 2</a> (#7)</li><li><a href="https://comicvine.gamespot.com/x-men-epic-collection-proteus/4050-129905/">X-Men Epic Collection: Proteus</a> (#7)</li><li><a href="https://comicvine.gamespot.com/alpha-flight-by-john-byrne-omnibus/4050-98560/" data-ref-id="4050-98560">Alpha Flight By John Byrne Omnibus</a> (#8)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-incredible-hulk-15-volume-1/4000-851634/" data-ref-id="4000-851634">Marvel Masterworks: The Incredible Hulk Volume 15</a> (#8-9)</li><li><a href="https://comicvine.gamespot.com/captain-universe-power-unimaginable/4050-25914/">Captain Universe: Power Unimaginable</a> (#10)</li><li><a href="/incredible-hulk-regression/4050-51322/" data-ref-id="4050-51322">Incredible Hulk: Regression</a> (#12)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-going-gray/4050-132382/">Incredible Hulk Epic Collection: Going Gray</a> (#14-15)</li><li><a href="https://comicvine.gamespot.com/hulk-lifeform/4050-126604/">Hulk: Lifeform</a> (#16 (Main Story))</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-by-peter-david-omnibus-2-vol-2/4000-814564/" data-ref-id="4000-814564">Incredible Hulk By Peter David Omnibus Vol. 2</a> (#16-18)</li><li><a href="/incredible-hulk-epic-collection-ghost-of-the-past/4050-84592/" data-ref-id="4050-84592">The Incredible Hulk Epic Collection: Ghosts of the Past</a> (#18-19)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-by-peter-david-omnibus-3-vol-3/4000-856179/" data-ref-id="4000-856179">Incredible Hulk By Peter David Omnibus Vol. 3</a> (#19-20)</li><li><a href="https://comicvine.gamespot.com/incredible-hulk-epic-collection-future-imperfect/4050-97755/" data-ref-id="4050-97755">The Incredible Hulk Epic Collection: Future Imperfect</a> (#20)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-63-el-increible-hulk-u/4000-612271/">Coleccionable Marvel Héroes - El Increíble Hulk: Un monstruo entre nosotros</a> (#5-6) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccion-extra-superheroes-26/4000-610305/" data-ref-id="4000-610305">Coleccíon Extra Superhéroes #26</a> (#7) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-67-el-increible-hulk-m/4000-612303/">Coleccionable Marvel Héroes - El increíble Hulk: Muerte y Destino</a> (#7-9) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-56-alpha-flight-de-joh/4000-612264/">Coleccionable Marvel Héroes - Alpha Flight de John Byrne</a> (#8) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-46-el-increible-hulk-p/4000-612254/">Coleccionable Marvel Héroes - El Increíble Hulk: Perdonado</a> (#10-11) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#11) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-51-el-increible-hulk-l/4000-612259/">Coleccionable Marvel Héroes - El Increíble Hulk: La Encrucijada</a> (#12-13) (Spanish)</li></ul><p>Issue <a href="https://comicvine.gamespot.com/biblioteca-marvel-hulk-24/4000-285413/" data-ref-id="4000-285413">#5</a>, <a href="https://comicvine.gamespot.com/biblioteca-marvel-hulk-27/4000-285416/" data-ref-id="4000-285416">#6</a> &amp; <a href="https://comicvine.gamespot.com/biblioteca-marvel-hulk-29/4000-285418/" data-ref-id="4000-285418">#7</a> have been translated into Spanish.</p>', '1968', '20', 'https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2618116-hulkan01.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2863', 'Marvel Team-Up Annual', 'The Lords of Light and Darkness!', '31', '<p>Annuals to the first Marvel Team-Up series. These special double-sized issues brought some of the greates heroes together. Many years later, one single team up was published in 1997, and in 1998 most of the Annuals produced by Marvel were Team-Ups;</p><ul><li><a href="/daredevildeadpool-annual-97/4050-26448/" data-ref-id="4050-26448">Daredevil / Deadpool ''97</a></li><li><a href="//www.comicvine.com/silver-surfer-thor-annual-98/4050-39906/" data-ref-id="4050-39906">Silver Surfer / Thor ''98</a></li><li><a href="//www.comicvine.com/captain-america-98/4050-60452/" data-ref-id="4050-60452">Captain America / Citizen V ''98</a></li><li><a href="//www.comicvine.com/cable-machine-man-annual-98/4050-18365/" data-ref-id="4050-18365">Cable / Machine Man ''98</a></li><li><a href="/deadpooldeath-annual-98/4050-18606/" data-ref-id="4050-18606">Deadpool / Death ''98</a></li><li><a href="/heroes-for-hire-quicksilver-annual-98/4050-19807/" data-ref-id="4050-19807">Heroes for Hire / Quicksilver ''98</a></li><li><a href="/alpha-flight-inhumans-annual-98/4050-25658/" data-ref-id="4050-25658">Alpha Flight / Inhumans ''98</a></li><li><a href="/machine-manbastion-annual-98/4050-26009/" data-ref-id="4050-26009">Machine Man / Bastion ''98</a></li><li><a href="//www.comicvine.com/x-mendr-doom-annual-98/4050-26316/" data-ref-id="4050-26316">X-Men / Dr. Doom ''98</a></li><li><a href="/x-man-hulk-annual-98/4050-28192/" data-ref-id="4050-28192">X-Man / Hulk ''98</a></li><li><a href="//www.comicvine.com/avengers-squadron-supreme-annual-98/4050-30632/" data-ref-id="4050-30632">Avengers / Squadron Supreme ''98</a></li><li><a href="//www.comicvine.com/x-force-champions-annual-98/4050-34173/" data-ref-id="4050-34173">X-Force / Champions ''98</a></li><li><a href="/peter-parker-spider-man-elektra-annual-98/4050-39918/" data-ref-id="4050-39918">Peter Parker: Spider-Man / Elektra ''98</a></li><li><a href="//www.comicvine.com/the-incredible-hulk-and-sub-mariner-annual-98/4050-60434/" data-ref-id="4050-60434">The Incredible Hulk / Sub-Mariner ''98</a></li><li><a href="//www.comicvine.com/generation-x-annual-98/4050-60445/" data-ref-id="4050-60445">Generation X / Dracula ''98</a></li><li><a href="//www.comicvine.com/uncanny-x-men-fantastic-four-annual-98/4050-30468/" data-ref-id="4050-30468">Uncanny X-Men / Fantastic Four ''98</a></li><li><a href="//www.comicvine.com/iron-man-captain-america-annual-98/4050-30391/" data-ref-id="4050-30391">Iron Man / Captain America ''98</a></li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/xmen-epic-collection-second-genesis/4050-100394/" data-ref-id="4050-100394">X-Men Epic Collection: Second Genesis</a> (#1)</li><li><a href="https://comicvine.gamespot.com/luke-cage-avenger/4050-92377/" data-ref-id="4050-92377">Luke Cage: Avenger</a> (#4)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#4)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#4)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-shadows-and-light/4050-98729/" data-ref-id="4050-98729">Cloak and Dagger: Shadows and Light</a> (#6)</li><li><a href="https://comicvine.gamespot.com/new-mutants-epic-collection-renewal/4050-99448/" data-ref-id="4050-99448">New Mutants Epic Collection: Renewal</a> (#6)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-omnibus/4050-130070/">Cloak and Dagger Omnibus</a> (#6)</li><li><a href="/the-amazing-spider-man-the-complete-alien-costume-/4000-461312/" data-ref-id="4000-461312">The Amazing Spider-Man: The Complete Alien Costume Saga Book 1</a> (#7)</li></ul><h4>Non-U.S. Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/coleccion-frank-miller-el-universo-marvel-segun-fr/4050-105405/">Colección Frank Miller. El Universo Marvel según Frank Miller</a> (#4) (Spanish)</li><li><a href="https://comicvine.gamespot.com/coleccionable-marvel-heroes-6-spiderman-integral-f/4000-612211/" data-ref-id="4000-612211">Coleccionable Marvel Héroes: Spiderman: Integral Frank Miller </a>(#4) (Spanish)</li></ul><p>Translated into <a href="https://comicvine.gamespot.com/spiderman-marvel-team-up/4050-43280/" data-ref-id="4050-43280">Spanish</a>.</p>', '1976', '7', 'https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2432227-marvelteam_upannual1.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2865', 'Marvel Two-in-One Annual', 'Their Name Is Legion!', '31', '<p>Annual series to the Thing''s starring title, <a href="/marvel-two-in-one/4050-2696/" data-ref-id="4050-2696">Marvel Two-in-One</a>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-2-volume-2/4000-621669/" data-ref-id="4000-621669">Marvel Masterworks: Marvel Two-In-One vol. 2</a> (#1)</li><li><a href="/guardians-of-the-galaxy-solo-classic-omnibus/4050-85759/" data-ref-id="4050-85759">Guardians of the Galaxy Solo Classic Omnibus</a> (#2)</li><li><a href="https://comicvine.gamespot.com/gamora-guardian-of-the-galaxy/4050-94272/" data-ref-id="4050-94272">Gamora: Guardian of the Galaxy</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-avengers-17-volume-17/4000-613795/" data-ref-id="4000-613795">Marvel Masterworks: Avengers Volume 17</a> (#2)</li><li><a href="https://comicvine.gamespot.com/the-thanos-wars-infinity-origin/4050-118000/">The Thanos Wars: Infinity Origin</a> (#2)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-marvel-two-in-one-4-volume-4/4000-716964/" data-ref-id="4000-716964">Marvel Masterworks: Marvel Two-In-One Volume 4</a> (#2-3)</li><li><a href="/marvel-masterworks-marvel-two-in-one-5-volume-5/4000-819153/" data-ref-id="4000-819153">Marvel Masterworks: Marvel Two-In-One Volume 5</a> (#4)</li></ul><p>Translated into <a href="https://comicvine.gamespot.com/biblioteca-marvel-la-cosa/4050-41953/" data-ref-id="4050-41953">Spanish</a>.</p>', '1976', '7', 'https://comicvine.gamespot.com/a/uploads/scale_medium/0/4/14228-2865-15916-1-marvel-two-in-one-an.jpg', '0');
INSERT INTO volumes (id, name, firstIssue, publisherId, deck, startYear, numIssues, image, numLikes) VALUES ('2870', 'The Spectacular Spider-Man', 'Twice Stings the Tarantula!', '31', '<p>The second monthly Spider-Man series and the second most popular volume next to the Amazing Spider-Man that started back in the 1970''s. The cover-title started out as "<em>Peter Parker: The Spectacular Spider-Man</em>" (<a href="https://comicvine.gamespot.com/peter-parker-the-spectacular-spider-man/4050-139754/" data-ref-id="4050-139754">and became the indicia title for a few years mid-run</a>), but the "Peter Parker" part was dropped with issue 134. The comic lasted until 1998 for a total of 263 issues. A second volume named <em><a href="/spectacular-spider-man/4050-11069/" data-ref-id="4050-11069">Spectacular Spider-Man</a></em> started in 2003.</p><p>To see the annuals associated with this title <em><a href="/the-spectacular-spider-man-annual/4050-3012/" data-ref-id="4050-3012">The Spectacular Spider-Man Annual</a></em>.</p><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-spectacular-spider-man-1-vo/4000-606630/" data-ref-id="4000-606630">Marvel Masterworks: The Spectacular Spider-Man Volume 1</a> (#1-15)</li><li><a href="https://comicvine.gamespot.com/amazing-spider-man-epic-collection-the-goblin-live/4050-119744/">Amazing Spider-Man Epic Collection: The Goblin Lives</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/morbius-the-living-vampire-omnibus/4050-128226/">Morbius the Living Vampire Omnibus</a> (#6-8 &amp; 38)</li><li><a href="https://comicvine.gamespot.com/morbius-epic-collection-the-end-of-a-living-vampir/4050-136029/">Morbius Epic Collection: The End Of A Living Vampire</a> (#6-8 &amp; 38)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-champions-1-volume-1/4000-516959/" data-ref-id="4000-516959">Marvel Masterworks: The Champions Volume 1</a> (#17-18)</li><li><a href="https://comicvine.gamespot.com/champions-classic-the-complete-collection/4050-111662/">Champions Classic: The Complete Collection</a> (#17-18)</li><li><a href="/moon-knight-epic-collection-bad-moon-rising/4050-77333/" data-ref-id="4050-77333">Moon Knight Epic Collection: Bad Moon Rising</a> (#22-23)</li><li><a href="https://comicvine.gamespot.com/moon-knight-omnibus-1-volume-1/4000-824088/" data-ref-id="4000-824088">Moon Knight Omnibus Volume 1</a> (#22-23)</li><li><a href="https://comicvine.gamespot.com/spider-man-the-original-clone-saga/4050-41275/">Spider-Man: The Original Clone Saga</a> (#25-31, 149 &amp; 162-163)</li><li><a href="https://comicvine.gamespot.com/marvel-universe-by-frank-miller-omnibus/4050-116073/">Marvel Universe by Frank Miller Omnibus</a> (#27-28)</li><li><a href="/marvel-masterworks-the-spectacular-spider-man-3-vo/4000-772344/" data-ref-id="4000-772344">Marvel Masterworks: The Spectacular Spider-Man Volume 3</a> (#32-42)</li><li><a href="https://comicvine.gamespot.com/fantastic-fourspider-man-classic/4050-41406/">Fantastic Four/Spider-Man Classic</a> (#42)</li><li><a href="https://comicvine.gamespot.com/marvel-masterworks-the-spectacular-spider-man-4-vo/4000-907536/" data-ref-id="4000-907536">Marvel Masterworks: The Spectacular Spider-Man Volume 4</a> (#43-55)</li><li><a href="https://comicvine.gamespot.com/spider-man-by-john-byrne-omnibus/4050-121104/">Spider-Man By John Byrne Omnibus</a> (#58)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-shadows-and-light/4050-98729/" data-ref-id="4050-98729">Cloak and Dagger: Shadows and Light</a> (#64, 69-70, 81-82 &amp; 94-96)</li><li><a href="https://comicvine.gamespot.com/cloak-and-dagger-omnibus/4050-130070/">Cloak and Dagger Omnibus</a> (#64, 69-70, 81-82 &amp; 94-96)</li><li><a href="https://comicvine.gamespot.com/the-punisher-back-to-the-war-omnibus/4050-104072/" data-ref-id="4050-104072">The Punisher: Back To the War Omnibus</a> (#81-84)</li><li><a href="https://comicvine.gamespot.com/the-marvel